var QUESTIONS_THEORY_15 = [
{type:"mcq",diff:"easy",en:{q:"What does the CIA triad stand for in Information Security?",opts:["Central Intelligence Agency","Confidentiality, Integrity, Availability","Control, Information, Access","Cybernet, Internet, Authentication"],ans:1,exp:"The CIA triad stands for Confidentiality, Integrity, and Availability. It is a foundational model in information security designed to guide policies for data protection. Confidentiality prevents unauthorized access, Integrity ensures data is unaltered, and Availability guarantees access to authorized users."},hi:{q:"सूचना सुरक्षा (Information Security) में CIA ट्राइड (triad) का पूर्ण रूप क्या है?",opts:["सेंट्रल इंटेलिजेंस एजेंसी","गोपनीयता (Confidentiality), अखंडता (Integrity), उपलब्धता (Availability)","कंट्रोल, इंफॉर्मेशन, एक्सेस","साइबरनेट, इंटरनेट, ऑथेंटिकेशन"],ans:1,exp:"CIA ट्राइड का अर्थ गोपनीयता, अखंडता और उपलब्धता है। यह सूचना सुरक्षा में एक मूलभूत मॉडल है जिसे डेटा सुरक्षा के लिए नीतियों का मार्गदर्शन करने के लिए डिज़ाइन किया गया है। गोपनीयता अनधिकृत पहुंच को रोकती है, अखंडता यह सुनिश्चित करती है कि डेटा अपरिवर्तित है, और उपलब्धता अधिकृत उपयोगकर्ताओं को पहुंच की गारंटी देती है।"}},
{type:"mcq",diff:"easy",en:{q:"What is a computer virus?",opts:["A hardware component","A benign system utility","A malicious program that replicates by attaching itself to other files","A network protocol"],ans:2,exp:"A computer virus is a type of malicious software (malware) that, when executed, replicates itself by modifying other computer programs and inserting its own code. It requires a host file to spread and can cause significant damage to data and systems."},hi:{q:"कंप्यूटर वायरस क्या है?",opts:["एक हार्डवेयर घटक","एक हानिरहित सिस्टम यूटिलिटी","एक दुर्भावनापूर्ण प्रोग्राम जो अन्य फ़ाइलों से जुड़कर खुद को दोहराता है","एक नेटवर्क प्रोटोकॉल"],ans:2,exp:"कंप्यूटर वायरस एक प्रकार का दुर्भावनापूर्ण सॉफ़्टवेयर (मैलवेयर) है, जो निष्पादित होने पर अन्य कंप्यूटर प्रोग्रामों को संशोधित करके और अपना कोड डालकर खुद को दोहराता है। इसे फैलने के लिए एक होस्ट फ़ाइल की आवश्यकता होती है और यह डेटा और सिस्टम को महत्वपूर्ण नुकसान पहुंचा सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the primary function of a Network Firewall?",opts:["To speed up internet connection","To block all incoming traffic","To monitor and filter incoming and outgoing network traffic based on security rules","To encrypt all local hard drives"],ans:2,exp:"A network firewall acts as a barrier between a trusted internal network and an untrusted external network (like the Internet). It continuously monitors and filters network traffic based on an organization's previously established security policies to prevent malicious access."},hi:{q:"नेटवर्क फ़ायरवॉल का प्राथमिक कार्य क्या है?",opts:["इंटरनेट कनेक्शन को तेज करना","सभी इनकमिंग ट्रैफ़िक को ब्लॉक करना","सुरक्षा नियमों के आधार पर आने वाले और जाने वाले नेटवर्क ट्रैफ़िक की निगरानी और फ़िल्टर करना","सभी स्थानीय हार्ड ड्राइव को एन्क्रिप्ट करना"],ans:2,exp:"एक नेटवर्क फ़ायरवॉल एक विश्वसनीय आंतरिक नेटवर्क और एक अविश्वसनीय बाहरी नेटवर्क (जैसे इंटरनेट) के बीच बाधा के रूप में कार्य करता है। यह दुर्भावनापूर्ण पहुंच को रोकने के लिए संगठन की पूर्व स्थापित सुरक्षा नीतियों के आधार पर नेटवर्क ट्रैफ़िक की लगातार निगरानी और फ़िल्टर करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is 'Phishing' in cyber security?",opts:["A method of encrypting data","A fraudulent attempt to obtain sensitive information by disguising as a trustworthy entity","A hardware failure","A technique to boost website performance"],ans:1,exp:"Phishing is a social engineering attack where cybercriminals impersonate legitimate organizations via email, text, or fake websites. The goal is to deceive victims into providing sensitive data, such as passwords, credit card numbers, or social security details."},hi:{q:"साइबर सुरक्षा में 'फिशिंग' (Phishing) क्या है?",opts:["डेटा एन्क्रिप्ट करने की एक विधि","एक भरोसेमंद इकाई के रूप में भेष बदलकर संवेदनशील जानकारी प्राप्त करने का धोखाधड़ीपूर्ण प्रयास","एक हार्डवेयर विफलता","वेबसाइट के प्रदर्शन को बढ़ाने की एक तकनीक"],ans:1,exp:"फिशिंग एक सोशल इंजीनियरिंग हमला है जहां साइबर अपराधी ईमेल, टेक्स्ट या नकली वेबसाइटों के माध्यम से वैध संगठनों का रूप धारण करते हैं। इसका उद्देश्य पीड़ितों को पासवर्ड, क्रेडिट कार्ड नंबर या सामाजिक सुरक्षा विवरण जैसे संवेदनशील डेटा प्रदान करने के लिए धोखा देना है।"}},
{type:"mcq",diff:"easy",en:{q:"In which year was the Information Technology (IT) Act enacted in India?",opts:["1998","2000","2005","2008"],ans:1,exp:"The Information Technology Act, 2000 (also known as ITA-2000, or the IT Act) was notified on October 17, 2000. It is the primary law in India dealing with cybercrime and electronic commerce, providing legal recognition for electronic transactions."},hi:{q:"भारत में सूचना प्रौद्योगिकी (IT) अधिनियम किस वर्ष अधिनियमित (enacted) किया गया था?",opts:["1998","2000","2005","2008"],ans:1,exp:"सूचना प्रौद्योगिकी अधिनियम, 2000 (जिसे ITA-2000 या IT अधिनियम के रूप में भी जाना जाता है) 17 अक्टूबर, 2000 को अधिसूचित किया गया था। यह भारत में साइबर अपराध और इलेक्ट्रॉनिक वाणिज्य से निपटने वाला प्राथमिक कानून है, जो इलेक्ट्रॉनिक लेनदेन के लिए कानूनी मान्यता प्रदान करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the process of converting plaintext into unreadable scrambled text called?",opts:["Decryption","Hashing","Encryption","Formatting"],ans:2,exp:"Encryption is the cryptographic process of encoding plaintext data into an unreadable format known as ciphertext. This ensures that even if unauthorized parties intercept the data, they cannot understand it without the corresponding decryption key."},hi:{q:"प्लेनटेक्स्ट को अपठनीय स्क्रैम्बल्ड टेक्स्ट में बदलने की प्रक्रिया को क्या कहा जाता है?",opts:["डिक्रिप्शन","हैशिंग","एन्क्रिप्शन","फॉर्मेटिंग"],ans:2,exp:"एन्क्रिप्शन प्लेनटेक्स्ट डेटा को अपठनीय प्रारूप में एन्कोड करने की क्रिप्टोग्राफ़िक प्रक्रिया है जिसे सिफरटेक्स्ट (ciphertext) के रूप में जाना जाता है। यह सुनिश्चित करता है कि भले ही अनधिकृत पक्ष डेटा को इंटरसेप्ट कर लें, वे संबंधित डिक्रिप्शन कुंजी के बिना इसे नहीं समझ सकते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What does the 'S' stand for in HTTPS?",opts:["System","Standard","Secure","Server"],ans:2,exp:"The 'S' in HTTPS stands for Secure. Hypertext Transfer Protocol Secure (HTTPS) uses SSL/TLS protocols to encrypt the communication between a user's web browser and the web server, protecting data from eavesdropping and tampering."},hi:{q:"HTTPS में 'S' का क्या अर्थ है?",opts:["सिस्टम","स्टैंडर्ड","सिक्योर (Secure)","सर्वर"],ans:2,exp:"HTTPS में 'S' का अर्थ सिक्योर है। हाइपरटेक्स्ट ट्रांसफर प्रोटोकॉल सिक्योर (HTTPS) उपयोगकर्ता के वेब ब्राउज़र और वेब सर्वर के बीच संचार को एन्क्रिप्ट करने के लिए SSL/TLS प्रोटोकॉल का उपयोग करता है, जिससे डेटा को ईव्सड्रॉपिंग (छिपकर सुनने) और छेड़छाड़ से बचाया जा सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is an example of Antivirus software?",opts:["Notepad","Windows Explorer","Norton","Microsoft Word"],ans:2,exp:"Norton is a well-known commercial antivirus and anti-malware software product. Antivirus software is designed to detect, prevent, and remove malicious software, utilizing signature-based detection and heuristic analysis to protect the system."},hi:{q:"निम्नलिखित में से कौन सा एंटीवायरस सॉफ़्टवेयर का एक उदाहरण है?",opts:["नोटपैड","विंडोज एक्सप्लोरर","नॉर्टन (Norton)","माइक्रोसॉफ्ट वर्ड"],ans:2,exp:"नॉर्टन एक प्रसिद्ध व्यावसायिक एंटीवायरस और एंटी-मैलवेयर सॉफ़्टवेयर उत्पाद है। एंटीवायरस सॉफ़्टवेयर को सिस्टम की सुरक्षा के लिए सिग्नेचर-आधारित पहचान और अनुमानी (heuristic) विश्लेषण का उपयोग करके दुर्भावनापूर्ण सॉफ़्टवेयर का पता लगाने, रोकने और हटाने के लिए डिज़ाइन किया गया है।"}},
{type:"mcq",diff:"easy",en:{q:"What is 'Malware'?",opts:["A hardware device","A generic term for any malicious software","A secure networking protocol","A type of firewall"],ans:1,exp:"Malware is a portmanteau for 'malicious software'. It acts as a broad umbrella term that encompasses viruses, worms, trojans, ransomware, spyware, and any other code intentionally designed to cause damage or exploit a computer system."},hi:{q:"'मैलवेयर' (Malware) क्या है?",opts:["एक हार्डवेयर डिवाइस","किसी भी दुर्भावनापूर्ण सॉफ़्टवेयर के लिए एक सामान्य शब्द","एक सुरक्षित नेटवर्किंग प्रोटोकॉल","एक प्रकार का फ़ायरवॉल"],ans:1,exp:"मैलवेयर 'malicious software' (दुर्भावनापूर्ण सॉफ़्टवेयर) का संक्षिप्त रूप है। यह एक व्यापक शब्द है जिसमें वायरस, वर्म्स, ट्रोजन, रैनसमवेयर, स्पाइवेयर और जानबूझकर किसी कंप्यूटर सिस्टम को नुकसान पहुंचाने या शोषण करने के लिए डिज़ाइन किया गया कोई अन्य कोड शामिल है।"}},
{type:"mcq",diff:"easy",en:{q:"Which malicious program masquerades as a legitimate, useful application to trick users into installing it?",opts:["Worm","Ransomware","Trojan Horse","Spam"],ans:2,exp:"A Trojan Horse is a type of malware that disguises itself as benign or desirable software. Unlike viruses or worms, Trojans do not self-replicate; they rely entirely on user interaction (like downloading an infected attachment) to infiltrate the system."},hi:{q:"कौन सा दुर्भावनापूर्ण प्रोग्राम उपयोगकर्ताओं को इसे स्थापित करने के लिए धोखा देने के लिए एक वैध, उपयोगी एप्लिकेशन का रूप धारण करता है?",opts:["वर्म (Worm)","रैनसमवेयर","ट्रोजन हॉर्स (Trojan Horse)","स्पैम"],ans:2,exp:"ट्रोजन हॉर्स एक प्रकार का मैलवेयर है जो खुद को सौम्य या वांछनीय सॉफ़्टवेयर के रूप में प्रच्छन्न करता है। वायरस या वर्म्स के विपरीत, ट्रोजन स्वयं-प्रतिकृति (self-replicate) नहीं करते हैं; वे सिस्टम में घुसपैठ करने के लिए पूरी तरह से उपयोगकर्ता की बातचीत (जैसे संक्रमित अनुलग्नक डाउनलोड करना) पर निर्भर करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What is the primary characteristic of a 'Worm' in computer security?",opts:["It encrypts user files for ransom","It requires a host file to execute","It self-replicates and spreads across networks without human intervention","It displays unwanted advertisements"],ans:2,exp:"A computer worm is a standalone malware computer program that replicates itself in order to spread to other computers. It relies heavily on security failures and computer networks to spread automatically, distinguishing it from viruses that need user action."},hi:{q:"कंप्यूटर सुरक्षा में 'वर्म' (Worm) की प्राथमिक विशेषता क्या है?",opts:["यह फिरौती के लिए उपयोगकर्ता फ़ाइलों को एन्क्रिप्ट करता है","इसे निष्पादित करने के लिए एक होस्ट फ़ाइल की आवश्यकता होती है","यह मानवीय हस्तक्षेप के बिना खुद को दोहराता है और नेटवर्क में फैलता है","यह अवांछित विज्ञापन प्रदर्शित करता है"],ans:2,exp:"कंप्यूटर वर्म एक स्टैंडअलोन मैलवेयर कंप्यूटर प्रोग्राम है जो अन्य कंप्यूटरों में फैलने के लिए खुद को दोहराता है। यह स्वचालित रूप से फैलने के लिए सुरक्षा विफलताओं और कंप्यूटर नेटवर्क पर बहुत अधिक निर्भर करता है, जो इसे उन वायरस से अलग करता है जिन्हें उपयोगकर्ता की कार्रवाई की आवश्यकता होती है।"}},
{type:"mcq",diff:"easy",en:{q:"What type of malware locks or encrypts a user's data and demands payment for the decryption key?",opts:["Adware","Ransomware","Spyware","Keylogger"],ans:1,exp:"Ransomware is a highly destructive form of cryptovirology. It encrypts the victim's personal files, rendering them inaccessible, and extorts a ransom (often in cryptocurrency like Bitcoin) from the victim to supposedly restore access to the data."},hi:{q:"किस प्रकार का मैलवेयर उपयोगकर्ता के डेटा को लॉक या एन्क्रिप्ट करता है और डिक्रिप्शन कुंजी (key) के लिए भुगतान की मांग करता है?",opts:["एडवेयर","रैनसमवेयर (Ransomware)","स्पाइवेयर","कीलॉगर"],ans:1,exp:"रैनसमवेयर क्रिप्टोवायरोलॉजी का एक अत्यधिक विनाशकारी रूप है। यह पीड़ित की व्यक्तिगत फाइलों को एन्क्रिप्ट करता है, जिससे वे अप्राप्य हो जाते हैं, और डेटा तक पहुंच बहाल करने के लिए पीड़ित से फिरौती (अक्सर बिटकॉइन जैसी क्रिप्टोकरेंसी में) की वसूली करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is 'Authentication' in access control?",opts:["Determining what resources a user can access","The process of verifying the identity of a user or system","Encrypting a user's password","Tracking user activities"],ans:1,exp:"Authentication is the initial phase in access control where a system verifies the identity of a user, device, or process. This is typically achieved using credentials like passwords, biometric scans, or security tokens before granting entry."},hi:{q:"एक्सेस कंट्रोल में 'प्रमाणीकरण' (Authentication) क्या है?",opts:["यह निर्धारित करना कि उपयोगकर्ता किन संसाधनों तक पहुंच सकता है","किसी उपयोगकर्ता या सिस्टम की पहचान सत्यापित करने की प्रक्रिया","उपयोगकर्ता के पासवर्ड को एन्क्रिप्ट करना","उपयोगकर्ता की गतिविधियों को ट्रैक करना"],ans:1,exp:"प्रमाणीकरण एक्सेस कंट्रोल का प्रारंभिक चरण है जहां कोई सिस्टम किसी उपयोगकर्ता, उपकरण या प्रक्रिया की पहचान की पुष्टि करता है। यह आम तौर पर प्रवेश देने से पहले पासवर्ड, बायोमेट्रिक स्कैन या सुरक्षा टोकन जैसी साख (credentials) का उपयोग करके प्राप्त किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"After authentication, what determines the specific permissions and resources a user is allowed to access?",opts:["Identification","Authorization","Accounting","Auditing"],ans:1,exp:"Authorization occurs immediately after authentication. It is the process of enforcing access control policies to determine if the authenticated user has the explicit permissions required to read, write, or execute specific system resources or files."},hi:{q:"प्रमाणीकरण के बाद, क्या निर्धारित करता है कि उपयोगकर्ता को किन विशिष्ट अनुमतियों और संसाधनों तक पहुंचने की अनुमति है?",opts:["पहचान (Identification)","प्राधिकरण (Authorization)","लेखांकन (Accounting)","ऑडिटिंग"],ans:1,exp:"प्राधिकरण प्रमाणीकरण के तुरंत बाद होता है। यह यह निर्धारित करने के लिए एक्सेस कंट्रोल नीतियों को लागू करने की प्रक्रिया है कि क्या प्रमाणित उपयोगकर्ता के पास विशिष्ट सिस्टम संसाधनों या फ़ाइलों को पढ़ने, लिखने या निष्पादित करने के लिए आवश्यक स्पष्ट अनुमतियां हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is considered a Biometric authentication method?",opts:["A strong password","A smart card","Fingerprint scanning","An OTP sent to mobile"],ans:2,exp:"Biometric authentication utilizes unique biological or physical characteristics to verify identity. Common examples include fingerprint scanning, iris recognition, facial recognition, and voice analysis, which are much harder to forge than passwords."},hi:{q:"निम्नलिखित में से किसे बायोमेट्रिक (Biometric) प्रमाणीकरण विधि माना जाता है?",opts:["एक मजबूत पासवर्ड","एक स्मार्ट कार्ड","फिंगरप्रिंट स्कैनिंग","मोबाइल पर भेजा गया OTP"],ans:2,exp:"बायोमेट्रिक प्रमाणीकरण पहचान सत्यापित करने के लिए अद्वितीय जैविक या शारीरिक विशेषताओं का उपयोग करता है। सामान्य उदाहरणों में फिंगरप्रिंट स्कैनिंग, आईरिस पहचान, चेहरे की पहचान और आवाज विश्लेषण शामिल हैं, जिन्हें पासवर्ड की तुलना में जाली बनाना बहुत कठिन है।"}},
{type:"mcq",diff:"easy",en:{q:"What does SSL stand for in web security?",opts:["System Secure Link","Secure Sockets Layer","Standard Security Logic","Safe Server Layer"],ans:1,exp:"SSL stands for Secure Sockets Layer. It is a deprecated, yet historically significant, cryptographic protocol designed to provide communication security over a computer network by encrypting the link between a web server and a browser."},hi:{q:"वेब सुरक्षा में SSL का पूर्ण रूप क्या है?",opts:["सिस्टम सिक्योर लिंक","सिक्योर सॉकेट्स लेयर (Secure Sockets Layer)","स्टैंडर्ड सिक्योरिटी लॉजिक","सेफ सर्वर लेयर"],ans:1,exp:"SSL का अर्थ सिक्योर सॉकेट्स लेयर है। यह एक पुराना, लेकिन ऐतिहासिक रूप से महत्वपूर्ण, क्रिप्टोग्राफ़िक प्रोटोकॉल है जिसे वेब सर्वर और ब्राउज़र के बीच लिंक को एन्क्रिप्ट करके कंप्यूटर नेटवर्क पर संचार सुरक्षा प्रदान करने के लिए डिज़ाइन किया गया है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the purpose of taking regular Data Backups?",opts:["To increase internet speed","To prevent hardware overheating","To ensure data can be recovered in case of loss, corruption, or ransomware attacks","To stop unauthorized network access"],ans:2,exp:"Data backups involve creating routine copies of critical digital information. This ensures continuity and disaster recovery, allowing organizations to restore data seamlessly if the original files are deleted, corrupted, or held hostage by ransomware."},hi:{q:"नियमित डेटा बैकअप (Data Backup) लेने का क्या उद्देश्य है?",opts:["इंटरनेट की गति बढ़ाने के लिए","हार्डवेयर को ज़्यादा गरम होने से रोकने के लिए","यह सुनिश्चित करने के लिए कि डेटा हानि, भ्रष्टाचार या रैनसमवेयर हमलों के मामले में डेटा पुनर्प्राप्त किया जा सकता है","अनधिकृत नेटवर्क पहुंच को रोकने के लिए"],ans:2,exp:"डेटा बैकअप में महत्वपूर्ण डिजिटल जानकारी की नियमित प्रतियां बनाना शामिल है। यह निरंतरता और आपदा पुनर्प्राप्ति (disaster recovery) सुनिश्चित करता है, जिससे संगठन डेटा को मूल फ़ाइलों के हटाए जाने, दूषित होने या रैनसमवेयर द्वारा बंधक बनाए जाने पर मूल रूप से पुनर्स्थापित कर सकते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which term describes an ethical security professional who hacks into systems with permission to find vulnerabilities?",opts:["Black Hat Hacker","White Hat Hacker","Grey Hat Hacker","Script Kiddie"],ans:1,exp:"A White Hat Hacker (or ethical hacker) uses penetration testing and offensive security techniques to probe systems with the owner's explicit permission. Their objective is to discover and patch vulnerabilities before malicious actors can exploit them."},hi:{q:"कौन सा शब्द एक नैतिक सुरक्षा पेशेवर का वर्णन करता है जो कमजोरियों को खोजने के लिए अनुमति के साथ सिस्टम में हैक करता है?",opts:["ब्लैक हैट हैकर","व्हाइट हैट हैकर (White Hat Hacker)","ग्रे हैट हैकर","स्क्रिप्ट किडी"],ans:1,exp:"एक व्हाइट हैट हैकर (या एथिकल हैकर) मालिक की स्पष्ट अनुमति के साथ सिस्टम की जांच करने के लिए प्रवेश परीक्षण (penetration testing) और आक्रामक सुरक्षा तकनीकों का उपयोग करता है। उनका उद्देश्य दुर्भावनापूर्ण अभिनेताओं द्वारा उनका शोषण करने से पहले कमजोरियों को खोजना और पैच करना है।"}},
{type:"mcq",diff:"easy",en:{q:"What is 'Cyberbullying'?",opts:["A virus that attacks school networks","The use of digital communication tools to harass, threaten, or humiliate an individual","Stealing banking information","Upgrading PC hardware"],ans:1,exp:"Cyberbullying involves the malicious use of electronic communication platforms—like social media, forums, or messaging apps—to repeatedly harass, embarrass, or intimidate individuals, which is a serious behavioral and legal issue in cyberspace."},hi:{q:"'साइबरबुलिंग' (Cyberbullying) क्या है?",opts:["एक वायरस जो स्कूल नेटवर्क पर हमला करता है","किसी व्यक्ति को परेशान करने, धमकाने या अपमानित करने के लिए डिजिटल संचार उपकरणों का उपयोग","बैंकिंग जानकारी चुराना","पीसी हार्डवेयर को अपग्रेड करना"],ans:1,exp:"साइबरबुलिंग में इलेक्ट्रॉनिक संचार प्लेटफॉर्म (जैसे सोशल मीडिया, फ़ोरम या मैसेजिंग ऐप) का दुर्भावनापूर्ण उपयोग शामिल है, ताकि व्यक्तियों को बार-बार परेशान, शर्मिंदा या डराया जा सके, जो साइबर स्पेस में एक गंभीर व्यवहार और कानूनी मुद्दा है।"}},
{type:"mcq",diff:"easy",en:{q:"Which type of malware secretly monitors user activity and collects personal information without consent?",opts:["Worm","Spyware","Ransomware","Logic Bomb"],ans:1,exp:"Spyware is a stealthy malware variant designed to observe and record user behavior, keystrokes, and browsing habits. It secretly transmits this harvested personal and financial data to remote servers controlled by cybercriminals."},hi:{q:"किस प्रकार का मैलवेयर गुप्त रूप से उपयोगकर्ता की गतिविधि पर नज़र रखता है और सहमति के बिना व्यक्तिगत जानकारी एकत्र करता है?",opts:["वर्म","स्पाइवेयर (Spyware)","रैनसमवेयर","लॉजिक बॉम्ब"],ans:1,exp:"स्पाइवेयर एक गुप्त मैलवेयर संस्करण है जिसे उपयोगकर्ता के व्यवहार, कीस्ट्रोक्स और ब्राउज़िंग आदतों का निरीक्षण और रिकॉर्ड करने के लिए डिज़ाइन किया गया है। यह गुप्त रूप से इस एकत्रित व्यक्तिगत और वित्तीय डेटा को साइबर अपराधियों द्वारा नियंत्रित दूरस्थ सर्वर तक पहुंचाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does VPN stand for?",opts:["Virtual Private Network","Virtual Public Node","Visual Protection Network","Verified Private Name"],ans:0,exp:"VPN stands for Virtual Private Network. It establishes a secure, encrypted tunnel over a less secure network (like the public internet), hiding the user's IP address and protecting data transit from unauthorized interception."},hi:{q:"VPN का पूर्ण रूप क्या है?",opts:["वर्चुअल प्राइवेट नेटवर्क (Virtual Private Network)","वर्चुअल पब्लिक नोड","विजुअल प्रोटेक्शन नेटवर्क","वेरिफाइड प्राइवेट नेम"],ans:0,exp:"VPN का अर्थ वर्चुअल प्राइवेट नेटवर्क है। यह कम सुरक्षित नेटवर्क (जैसे सार्वजनिक इंटरनेट) पर एक सुरक्षित, एन्क्रिप्टेड सुरंग (tunnel) स्थापित करता है, उपयोगकर्ता का IP पता छुपाता है और डेटा पारगमन को अनधिकृत अवरोधन से बचाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is 'Spam' in the context of email communication?",opts:["A secure messaging protocol","Unsolicited, bulk junk emails often sent for advertising or malicious purposes","An email attachment format","A type of email server"],ans:1,exp:"Spam refers to electronic junk mail consisting of unsolicited, bulk messages. Cybercriminals frequently use spam to distribute malware payloads, conduct phishing campaigns, or simply overwhelm users with deceptive advertisements."},hi:{q:"ईमेल संचार के संदर्भ में 'स्पैम' (Spam) क्या है?",opts:["एक सुरक्षित मैसेजिंग प्रोटोकॉल","अवांछित, थोक जंक ईमेल जो अक्सर विज्ञापन या दुर्भावनापूर्ण उद्देश्यों के लिए भेजे जाते हैं","एक ईमेल अटैचमेंट प्रारूप","एक प्रकार का ईमेल सर्वर"],ans:1,exp:"स्पैम का तात्पर्य इलेक्ट्रॉनिक जंक मेल से है जिसमें अवांछित, थोक संदेश होते हैं। साइबर अपराधी अक्सर मैलवेयर पेलोड वितरित करने, फिशिंग अभियान चलाने, या केवल भ्रामक विज्ञापनों से उपयोगकर्ताओं को अभिभूत करने के लिए स्पैम का उपयोग करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is an example of Physical Security for a computer system?",opts:["Installing a firewall","Using biometric locks on the server room door","Encrypting the hard drive","Running an antivirus scan"],ans:1,exp:"Physical security involves tangible mechanisms designed to prevent unauthorized physical access to facilities and hardware. Biometric locks, CCTV cameras, security guards, and server racks are prime examples of physical security controls."},hi:{q:"निम्नलिखित में से कौन सा कंप्यूटर सिस्टम के लिए भौतिक सुरक्षा (Physical Security) का एक उदाहरण है?",opts:["फ़ायरवॉल स्थापित करना","सर्वर रूम के दरवाजे पर बायोमेट्रिक लॉक का उपयोग करना","हार्ड ड्राइव को एन्क्रिप्ट करना","एंटीवायरस स्कैन चलाना"],ans:1,exp:"भौतिक सुरक्षा में सुविधाओं और हार्डवेयर तक अनधिकृत भौतिक पहुंच को रोकने के लिए डिज़ाइन किए गए मूर्त तंत्र (tangible mechanisms) शामिल हैं। बायोमेट्रिक ताले, सीसीटीवी कैमरे, सुरक्षा गार्ड और सर्वर रैक भौतिक सुरक्षा नियंत्रण के प्रमुख उदाहरण हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What is a 'Patch' in software terminology?",opts:["A physical cable","A piece of software designed to update a program or fix a vulnerability","A type of computer virus","A completely new operating system"],ans:1,exp:"A patch is a software update released by developers to fix bugs, improve performance, or critically address known security vulnerabilities. Regular patching is an essential practice in maintaining robust cyber hygiene."},hi:{q:"सॉफ़्टवेयर शब्दावली में 'पैच' (Patch) क्या है?",opts:["एक भौतिक केबल","प्रोग्राम को अपडेट करने या किसी भेद्यता (vulnerability) को ठीक करने के लिए डिज़ाइन किया गया सॉफ़्टवेयर","एक प्रकार का कंप्यूटर वायरस","एक पूरी तरह से नया ऑपरेटिंग सिस्टम"],ans:1,exp:"पैच एक सॉफ़्टवेयर अपडेट है जो डेवलपर्स द्वारा बग को ठीक करने, प्रदर्शन में सुधार करने या ज्ञात सुरक्षा कमजोरियों को गंभीर रूप से संबोधित करने के लिए जारी किया जाता है। मजबूत साइबर स्वच्छता बनाए रखने के लिए नियमित रूप से पैचिंग एक आवश्यक अभ्यास है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the primary motive of a 'Denial of Service' (DoS) attack?",opts:["To steal credit card numbers","To permanently delete files","To overwhelm a system or network resource, making it unavailable to legitimate users","To install an operating system"],ans:2,exp:"A DoS attack aims to disrupt normal operations by flooding the targeted host or network with an excessive amount of traffic or malicious requests. This exhausts the system's bandwidth or processing power, resulting in a denial of service to actual users."},hi:{q:"'डिनायल ऑफ सर्विस' (DoS) हमले का प्राथमिक उद्देश्य क्या है?",opts:["क्रेडिट कार्ड नंबर चुराना","फ़ाइलों को स्थायी रूप से हटाना","सिस्टम या नेटवर्क संसाधन पर भारी ट्रैफ़िक भेजना, जिससे यह वैध उपयोगकर्ताओं के लिए अनुपलब्ध हो जाए","ऑपरेटिंग सिस्टम स्थापित करना"],ans:2,exp:"DoS हमले का उद्देश्य लक्षित होस्ट या नेटवर्क पर अत्यधिक मात्रा में ट्रैफ़िक या दुर्भावनापूर्ण अनुरोध भेजकर सामान्य संचालन को बाधित करना है। यह सिस्टम के बैंडविड्थ या प्रसंस्करण शक्ति को समाप्त कर देता है, जिसके परिणामस्वरूप वास्तविक उपयोगकर्ताओं को सेवा से वंचित (denial of service) कर दिया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does the term 'Social Engineering' mean in cyber security?",opts:["Programming social media algorithms","Manipulating people into performing actions or divulging confidential information","Building secure physical offices","Encrypting social network data"],ans:1,exp:"Social engineering exploits human psychology rather than technical hacking techniques. Attackers use deception, manipulation, and persuasion to trick employees or individuals into breaking normal security procedures and revealing sensitive data."},hi:{q:"साइबर सुरक्षा में 'सोशल इंजीनियरिंग' (Social Engineering) शब्द का क्या अर्थ है?",opts:["सोशल मीडिया एल्गोरिदम की प्रोग्रामिंग","लोगों को कार्य करने या गोपनीय जानकारी का खुलासा करने के लिए हेरफेर करना","सुरक्षित भौतिक कार्यालयों का निर्माण","सोशल नेटवर्क डेटा को एन्क्रिप्ट करना"],ans:1,exp:"सोशल इंजीनियरिंग तकनीकी हैकिंग तकनीकों के बजाय मानव मनोविज्ञान का फायदा उठाता है। हमलावर कर्मचारियों या व्यक्तियों को सामान्य सुरक्षा प्रक्रियाओं को तोड़ने और संवेदनशील डेटा प्रकट करने के लिए छल, हेरफेर और अनुनय का उपयोग करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which software application is used to secretly record the keys struck on a keyboard?",opts:["Antivirus","Firewall","Keylogger","VPN"],ans:2,exp:"A Keylogger (keystroke logger) is a covert surveillance software or hardware tool. It intercepts and records every keystroke pressed by the user, allowing attackers to harvest passwords, personal messages, and credit card details seamlessly."},hi:{q:"कीबोर्ड पर दबाई गई कुंजियों को गुप्त रूप से रिकॉर्ड करने के लिए किस सॉफ़्टवेयर एप्लिकेशन का उपयोग किया जाता है?",opts:["एंटीवायरस","फ़ायरवॉल","कीलॉगर (Keylogger)","VPN"],ans:2,exp:"कीलॉगर एक गुप्त निगरानी सॉफ़्टवेयर या हार्डवेयर टूल है। यह उपयोगकर्ता द्वारा दबाए गए प्रत्येक कीस्ट्रोक को इंटरसेप्ट और रिकॉर्ड करता है, जिससे हमलावरों को पासवर्ड, व्यक्तिगत संदेश और क्रेडिट कार्ड विवरण आसानी से चुराने की अनुमति मिलती है।"}},
{type:"mcq",diff:"easy",en:{q:"What does 'Adware' primarily do?",opts:["Automatically displays or downloads unwanted advertising material","Encrypts hard drives","Protects against viruses","Boosts internet speed"],ans:0,exp:"Adware (Advertising-supported software) is a type of potentially unwanted program that bombards the user with intrusive popup ads, banners, and redirects. While not always inherently destructive, it heavily degrades system performance and user experience."},hi:{q:"'एडवेयर' (Adware) मुख्य रूप से क्या करता है?",opts:["स्वचालित रूप से अवांछित विज्ञापन सामग्री प्रदर्शित या डाउनलोड करता है","हार्ड ड्राइव को एन्क्रिप्ट करता है","वायरस से बचाता है","इंटरनेट की गति बढ़ाता है"],ans:0,exp:"एडवेयर (विज्ञापन-समर्थित सॉफ़्टवेयर) एक प्रकार का संभावित अवांछित प्रोग्राम है जो उपयोगकर्ता पर दखल देने वाले पॉपअप विज्ञापन, बैनर और रीडायरेक्ट की बमबारी करता है। हालांकि यह हमेशा विनाशकारी नहीं होता है, यह सिस्टम के प्रदर्शन और उपयोगकर्ता अनुभव को भारी रूप से कम करता है।"}},
{type:"tf",diff:"easy",en:{q:"Antivirus software physically prevents a computer's hardware from burning out due to overheating.",opts:["True","False"],ans:1,exp:"False. Antivirus software only protects against software-based threats like malware and viruses. It cannot monitor or prevent physical hardware damage such as component overheating or electrical short circuits."},hi:{q:"एंटीवायरस सॉफ़्टवेयर भौतिक रूप से कंप्यूटर के हार्डवेयर को अधिक गर्म होने के कारण जलने से रोकता है।",opts:["सही","गलत"],ans:1,exp:"गलत। एंटीवायरस सॉफ़्टवेयर केवल मैलवेयर और वायरस जैसे सॉफ़्टवेयर-आधारित खतरों से बचाता है। यह भौतिक हार्डवेयर क्षति जैसे घटक के अधिक गर्म होने या बिजली के शॉर्ट सर्किट की निगरानी या रोकथाम नहीं कर सकता है।"}},
{type:"tf",diff:"easy",en:{q:"The primary purpose of HTTPS is to encrypt the data transmitted between a web browser and a website.",opts:["True","False"],ans:0,exp:"True. HTTPS (Hypertext Transfer Protocol Secure) ensures that all communication data passing between the client's browser and the web server is encrypted via TLS, securing it from interception and tampering."},hi:{q:"HTTPS का प्राथमिक उद्देश्य वेब ब्राउज़र और वेबसाइट के बीच प्रेषित डेटा को एन्क्रिप्ट करना है।",opts:["सही","गलत"],ans:0,exp:"सही। HTTPS (हाइपरटेक्स्ट ट्रांसफर प्रोटोकॉल सिक्योर) यह सुनिश्चित करता है कि क्लाइंट के ब्राउज़र और वेब सर्वर के बीच गुजरने वाला सभी संचार डेटा TLS के माध्यम से एन्क्रिप्ट किया गया है, जो इसे अवरोधन और छेड़छाड़ से बचाता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which standard port number is designated for HTTPS traffic?",opts:["Port 80","Port 21","Port 443","Port 25"],ans:3,exp:"Port 443 is the universally recognized default port for establishing secure HTTP connections (HTTPS) via SSL/TLS. Conversely, Port 80 is used for unencrypted HTTP traffic, and Port 21 is reserved for FTP."},hi:{q:"HTTPS ट्रैफ़िक के लिए कौन सा मानक पोर्ट नंबर निर्दिष्ट है?",opts:["पोर्ट 80","पोर्ट 21","पोर्ट 443","पोर्ट 25"],ans:2,exp:"पोर्ट 443 SSL/TLS के माध्यम से सुरक्षित HTTP कनेक्शन (HTTPS) स्थापित करने के लिए विश्व स्तर पर मान्यता प्राप्त डिफ़ॉल्ट पोर्ट है। इसके विपरीत, पोर्ट 80 का उपयोग एन्क्रिप्टेड HTTP ट्रैफ़िक के लिए किया जाता है, और पोर्ट 21 FTP के लिए आरक्षित है।"}},
{type:"mcq",diff:"medium",en:{q:"How many keys are utilized in a Symmetric Encryption algorithm to securely communicate between two parties?",opts:["One shared key","Two different keys","Three keys","No keys"],ans:0,exp:"In Symmetric Encryption (like AES or DES), both the sender and the receiver utilize the exact same single secret key to both encrypt and decrypt the payload. Secure key distribution is the primary challenge of this method."},hi:{q:"दो पक्षों के बीच सुरक्षित रूप से संचार करने के लिए सममित एन्क्रिप्शन (Symmetric Encryption) एल्गोरिदम में कितनी कुंजियों (keys) का उपयोग किया जाता है?",opts:["एक साझा कुंजी (shared key)","दो अलग-अलग कुंजियाँ","तीन कुंजियाँ","कोई कुंजी नहीं"],ans:0,exp:"सममित एन्क्रिप्शन (जैसे AES या DES) में, प्रेषक और रिसीवर दोनों पेलोड को एन्क्रिप्ट और डिक्रिप्ट करने के लिए बिल्कुल उसी एक गुप्त कुंजी का उपयोग करते हैं। सुरक्षित कुंजी वितरण इस पद्धति की प्राथमिक चुनौती है।"}},
{type:"mcq",diff:"medium",en:{q:"Which specific section of the IT Act, 2000 deals with 'Hacking with Computer System' and computer-related offenses?",opts:["Section 43","Section 65","Section 66","Section 67"],ans:2,exp:"Section 66 of the Information Technology Act, 2000 specifically penalizes computer-related offenses. It outlines that anyone who acts fraudulently or dishonestly to damage or alter data (essentially hacking) faces imprisonment up to 3 years or a fine."},hi:{q:"IT अधिनियम, 2000 की कौन सी विशिष्ट धारा 'कंप्यूटर सिस्टम के साथ हैकिंग' और कंप्यूटर से संबंधित अपराधों से संबंधित है?",opts:["धारा 43","धारा 65","धारा 66","धारा 67"],ans:2,exp:"सूचना प्रौद्योगिकी अधिनियम, 2000 की धारा 66 विशेष रूप से कंप्यूटर से संबंधित अपराधों को दंडित करती है। यह रेखांकित करता है कि जो कोई भी डेटा को नुकसान पहुंचाने या बदलने के लिए धोखाधड़ी या बेईमानी से काम करता है (अनिवार्य रूप से हैकिंग) उसे 3 साल तक की कैद या जुर्माना का सामना करना पड़ता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the standard length of a MAC (Media Access Control) address?",opts:["32 bits","48 bits","64 bits","48 bits represented as 12 hexadecimal digits"],ans:3,exp:"A MAC address is a 48-bit unique hardware identifier assigned to network interface controllers (NICs). It is typically formatted as six groups of two hexadecimal digits (e.g., 00:1A:2B:3C:4D:5E) operating at the OSI Data Link layer."},hi:{q:"MAC (मीडिया एक्सेस कंट्रोल) पते की मानक लंबाई क्या है?",opts:["32 बिट्स","48 बिट्स","64 बिट्स","48 बिट्स जिन्हें 12 हेक्साडेसिमल अंकों के रूप में दर्शाया गया है"],ans:3,exp:"एक MAC पता एक 48-बिट अद्वितीय हार्डवेयर पहचानकर्ता है जो नेटवर्क इंटरफ़ेस नियंत्रकों (NICs) को सौंपा गया है। इसे आम तौर पर दो हेक्साडेसिमल अंकों के छह समूहों (उदा., 00:1A:2B:3C:4D:5E) के रूप में स्वरूपित किया जाता है जो OSI डेटा लिंक परत पर काम करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"What is the primary function of an Intrusion Detection System (IDS)?",opts:["To block all network traffic","To encrypt network traffic","To monitor network traffic for suspicious activity or policy violations and generate alerts","To manage user passwords"],ans:2,exp:"An Intrusion Detection System (IDS) is a passive monitoring tool. It continuously analyzes network packets or system logs against signature databases and anomaly baselines to detect and alert administrators of potential malicious breaches or policy violations."},hi:{q:"इंट्रूज़न डिटेक्शन सिस्टम (IDS) का प्राथमिक कार्य क्या है?",opts:["सभी नेटवर्क ट्रैफ़िक को ब्लॉक करना","नेटवर्क ट्रैफ़िक को एन्क्रिप्ट करना","संदिग्ध गतिविधि या नीति उल्लंघन के लिए नेटवर्क ट्रैफ़िक की निगरानी करना और अलर्ट उत्पन्न करना","उपयोगकर्ता पासवर्ड प्रबंधित करना"],ans:2,exp:"इंट्रूज़न डिटेक्शन सिस्टम (IDS) एक निष्क्रिय (passive) निगरानी उपकरण है। यह संभावित दुर्भावनापूर्ण उल्लंघनों या नीति उल्लंघनों का पता लगाने और प्रशासकों को सचेत करने के लिए सिग्नेचर डेटाबेस और विसंगति बेसलाइन के खिलाफ नेटवर्क पैकेट या सिस्टम लॉग का लगातार विश्लेषण करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What does IP Spoofing refer to in a network attack?",opts:["Creating fake IP addresses to speed up internet","The creation of IP packets with a forged source IP address to conceal the identity of the sender or impersonate another system","Encrypting IP packets for secure transmission","Assigning static IP addresses via DHCP"],ans:1,exp:"IP Spoofing is a technique where an attacker deliberately modifies the source IP address in the header of an IP packet. This forgery allows the attacker to bypass IP-based authentication, hide their true location, or launch DDoS amplification attacks."},hi:{q:"नेटवर्क हमले में IP स्पूफिंग (IP Spoofing) का क्या अर्थ है?",opts:["इंटरनेट को गति देने के लिए नकली IP पते बनाना","प्रेषक की पहचान छिपाने या किसी अन्य सिस्टम का रूप धारण करने के लिए जाली स्रोत IP पते के साथ IP पैकेट का निर्माण","सुरक्षित संचरण के लिए IP पैकेट एन्क्रिप्ट करना","DHCP के माध्यम से स्थिर IP पते निर्दिष्ट करना"],ans:1,exp:"IP स्पूफिंग एक ऐसी तकनीक है जहां एक हमलावर जानबूझकर IP पैकेट के हेडर में स्रोत IP पते को संशोधित करता है। यह जालसाजी हमलावर को IP-आधारित प्रमाणीकरण को बायपास करने, अपना वास्तविक स्थान छिपाने, या DDoS प्रवर्धन (amplification) हमले शुरू करने की अनुमति देती है।"}},
{type:"mcq",diff:"medium",en:{q:"In Directory Services, what does LDAP stand for?",opts:["Lightweight Directory Access Protocol","Local Directory Authentication Process","Logical Data Application Protocol","Large Directory Access Program"],ans:0,exp:"LDAP stands for Lightweight Directory Access Protocol. It is an open, vendor-neutral application protocol used for querying and modifying directory services over IP networks, essential for managing enterprise user identities and authentication."},hi:{q:"डायरेक्टरी सर्विसेज में LDAP का पूर्ण रूप क्या है?",opts:["लाइटवेट डायरेक्टरी एक्सेस प्रोटोकॉल (Lightweight Directory Access Protocol)","लोकल डायरेक्टरी ऑथेंटिकेशन प्रोसेस","लॉजिकल डेटा एप्लीकेशन प्रोटोकॉल","लार्ज डायरेक्टरी एक्सेस प्रोग्राम"],ans:0,exp:"LDAP का अर्थ लाइटवेट डायरेक्टरी एक्सेस प्रोटोकॉल है। यह एक खुला, वेंडर-न्यूट्रल एप्लिकेशन प्रोटोकॉल है जिसका उपयोग IP नेटवर्क पर निर्देशिका सेवाओं को क्वेरी और संशोधित करने के लिए किया जाता है, जो उद्यम उपयोगकर्ता पहचान और प्रमाणीकरण के प्रबंधन के लिए आवश्यक है।"}},
{type:"mcq",diff:"medium",en:{q:"Section 67 of the IT Act, 2000 deals primarily with which cyber offense?",opts:["Hacking wireless networks","Publishing or transmitting obscene material in electronic form","Software piracy","Bypassing biometric security"],ans:1,exp:"Section 67 explicitly outlaws the publishing, transmitting, or causing to be published in electronic form any material which is lascivious or appeals to the prurient interest. It acts as India's primary legal framework against digital obscenity."},hi:{q:"IT अधिनियम, 2000 की धारा 67 मुख्य रूप से किस साइबर अपराध से संबंधित है?",opts:["वायरलेस नेटवर्क की हैकिंग","इलेक्ट्रॉनिक रूप में अश्लील सामग्री (obscene material) प्रकाशित या प्रसारित करना","सॉफ्टवेयर पायरेसी","बायोमेट्रिक सुरक्षा को बायपास करना"],ans:1,exp:"धारा 67 स्पष्ट रूप से किसी भी ऐसी सामग्री को इलेक्ट्रॉनिक रूप में प्रकाशित करने, प्रसारित करने या प्रकाशित करने का कारण बनने पर रोक लगाती है जो कामुक है या कामुक रुचि को आकर्षित करती है। यह डिजिटल अश्लीलता के खिलाफ भारत के प्राथमिक कानूनी ढांचे के रूप में कार्य करता है।"}},
{type:"mcq",diff:"medium",en:{q:"In risk management, what is the fundamental difference between a 'Vulnerability' and a 'Threat'?",opts:["A vulnerability is an external attacker; a threat is an internal error","A vulnerability is a weakness in the system; a threat is a potential malicious event that exploits it","They are identical concepts","A vulnerability is a virus; a threat is a firewall"],ans:1,exp:"A Vulnerability is an inherent flaw, gap, or weakness in a system's design or configuration (e.g., unpatched software). A Threat is any external or internal circumstance or actor (e.g., a hacker) that can exploit that vulnerability to cause harm."},hi:{q:"जोखिम प्रबंधन में, 'भेद्यता' (Vulnerability) और 'खतरा' (Threat) के बीच मूल अंतर क्या है?",opts:["एक भेद्यता एक बाहरी हमलावर है; एक खतरा एक आंतरिक त्रुटि है","एक भेद्यता सिस्टम में एक कमजोरी है; एक खतरा एक संभावित दुर्भावनापूर्ण घटना है जो इसका फायदा उठाती है","वे समान अवधारणाएँ हैं","एक भेद्यता एक वायरस है; एक खतरा एक फ़ायरवॉल है"],ans:1,exp:"एक भेद्यता एक सिस्टम के डिजाइन या कॉन्फ़िगरेशन (उदा., अनपैच्ड सॉफ्टवेयर) में एक अंतर्निहित दोष, अंतर या कमजोरी है। एक खतरा कोई भी बाहरी या आंतरिक परिस्थिति या अभिनेता (उदा., एक हैकर) है जो नुकसान पहुंचाने के लिए उस भेद्यता का फायदा उठा सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"What does the 'Principle of Least Privilege' dictate in information security?",opts:["Users should have administrative rights at all times","Users are granted only the minimum level of access rights strictly necessary to perform their legitimate job functions","Users should change passwords daily","Users must be physically present to access data"],ans:1,exp:"The Principle of Least Privilege (PoLP) is a core security concept stating that users, programs, and processes should possess bare minimum access privileges. Limiting permissions heavily mitigates the potential damage from both internal errors and external compromises."},hi:{q:"सूचना सुरक्षा में 'न्यून्तम विशेषाधिकार का सिद्धांत' (Principle of Least Privilege) क्या निर्धारित करता है?",opts:["उपयोगकर्ताओं के पास हर समय प्रशासनिक अधिकार होने चाहिए","उपयोगकर्ताओं को अपने वैध नौकरी कार्यों को करने के लिए सख्ती से आवश्यक न्यूनतम स्तर के पहुंच अधिकार (access rights) दिए जाते हैं","उपयोगकर्ताओं को प्रतिदिन पासवर्ड बदलना चाहिए","डेटा तक पहुँचने के लिए उपयोगकर्ताओं को भौतिक रूप से उपस्थित होना चाहिए"],ans:1,exp:"प्रिंसिपल ऑफ लीस्ट प्रिविलेज (PoLP) एक मुख्य सुरक्षा अवधारणा है जिसमें कहा गया है कि उपयोगकर्ताओं, कार्यक्रमों और प्रक्रियाओं के पास न्यूनतम पहुंच विशेषाधिकार होने चाहिए। अनुमतियों को सीमित करने से आंतरिक त्रुटियों और बाहरी समझौते दोनों से संभावित नुकसान को काफी कम किया जा सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"At which layer of the OSI model does the SSL/TLS protocol conceptually operate to establish a secure connection?",opts:["Physical Layer","Data Link Layer","Between Transport and Application Layers","Network Layer"],ans:2,exp:"SSL (Secure Sockets Layer) and its successor TLS operate securely encrypting the TCP connection. Conceptually, they reside directly above the Transport layer (Layer 4) and below the Application layer (Layer 7), encapsulating application data before transmission."},hi:{q:"सुरक्षित कनेक्शन स्थापित करने के लिए SSL/TLS प्रोटोकॉल वैचारिक रूप से OSI मॉडल की किस परत (layer) पर काम करता है?",opts:["फिजिकल लेयर","डेटा लिंक लेयर","ट्रांसपोर्ट और एप्लिकेशन लेयर के बीच","नेटवर्क लेयर"],ans:2,exp:"SSL (सिक्योर सॉकेट्स लेयर) और इसका उत्तराधिकारी TLS सुरक्षित रूप से TCP कनेक्शन को एन्क्रिप्ट करते हुए काम करते हैं। वैचारिक रूप से, वे सीधे ट्रांसपोर्ट लेयर (लेयर 4) के ऊपर और एप्लिकेशन लेयर (लेयर 7) के नीचे रहते हैं, ट्रांसमिशन से पहले एप्लिकेशन डेटा को एनकैप्सुलेट करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"What is an 'Audit Trail' in the context of system security?",opts:["A software patch","A chronological record of system activities showing who accessed what data and when","A backup file","A firewall configuration tool"],ans:1,exp:"An audit trail (or audit log) is a secure, chronological record that tracks sequential activities and events occurring within a system. It provides irrefutable documentary evidence of operations, critical for digital forensics, compliance, and tracing security breaches."},hi:{q:"सिस्टम सुरक्षा के संदर्भ में 'ऑडिट ट्रेल' (Audit Trail) क्या है?",opts:["एक सॉफ़्टवेयर पैच","सिस्टम गतिविधियों का एक कालानुक्रमिक (chronological) रिकॉर्ड जो यह दर्शाता है कि किसने और कब किस डेटा तक पहुंच प्राप्त की","एक बैकअप फ़ाइल","एक फ़ायरवॉल कॉन्फ़िगरेशन उपकरण"],ans:1,exp:"ऑडिट ट्रेल (या ऑडिट लॉग) एक सुरक्षित, कालानुक्रमिक रिकॉर्ड है जो सिस्टम के भीतर होने वाली अनुक्रमिक गतिविधियों और घटनाओं को ट्रैक करता है। यह संचालन के अकाट्य दस्तावेजी साक्ष्य प्रदान करता है, जो डिजिटल फोरेंसिक, अनुपालन और सुरक्षा उल्लंघनों का पता लगाने के लिए महत्वपूर्ण है।"}},
{type:"mcq",diff:"medium",en:{q:"Which implementation is a primary example of Two-Factor Authentication (2FA)?",opts:["Entering a username and a password","Entering a password and then supplying an OTP sent via SMS to a mobile phone","Swiping an ID card twice","Using a password that is 16 characters long"],ans:1,exp:"Two-Factor Authentication (2FA) requires two distinct forms of identification: something the user 'knows' (a password) and something the user 'has' (a mobile device receiving an OTP). This dual-layer approach significantly impedes unauthorized access."},hi:{q:"टू-फैक्टर ऑथेंटिकेशन (2FA) का प्राथमिक उदाहरण कौन सा कार्यान्वयन है?",opts:["उपयोगकर्ता नाम और पासवर्ड दर्ज करना","पासवर्ड दर्ज करना और फिर मोबाइल फोन पर SMS के माध्यम से भेजा गया OTP प्रदान करना","आईडी कार्ड को दो बार स्वाइप करना","16 अक्षरों वाले पासवर्ड का उपयोग करना"],ans:1,exp:"टू-फैक्टर ऑथेंटिकेशन (2FA) के लिए पहचान के दो अलग-अलग रूपों की आवश्यकता होती है: कुछ ऐसा जो उपयोगकर्ता 'जानता' है (एक पासवर्ड) और कुछ ऐसा जो उपयोगकर्ता के पास 'है' (OTP प्राप्त करने वाला मोबाइल डिवाइस)। यह दोहरी परत दृष्टिकोण अनधिकृत पहुंच को महत्वपूर्ण रूप से बाधित करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Under Section 43 of the IT Act, 2000, what is the primary consequence for damaging a computer system without permission?",opts:["Life imprisonment","Death penalty","Liability to pay compensation to the person affected","Cancellation of passport"],ans:2,exp:"Section 43 outlines civil offenses related to unauthorized access, introducing a virus, or damaging a computer network. The primary penalty is a civil liability requiring the offender to pay proportional compensation to the affected party for the incurred losses."},hi:{q:"IT अधिनियम, 2000 की धारा 43 के तहत, बिना अनुमति के कंप्यूटर सिस्टम को नुकसान पहुंचाने का प्राथमिक परिणाम क्या है?",opts:["आजीवन कारावास","मृत्यु दंड","प्रभावित व्यक्ति को मुआवजा देने का दायित्व (Liability to pay compensation)","पासपोर्ट रद्द करना"],ans:2,exp:"धारा 43 अनधिकृत पहुंच, वायरस पेश करने या कंप्यूटर नेटवर्क को नुकसान पहुंचाने से संबंधित नागरिक अपराधों की रूपरेखा तैयार करती है। प्राथमिक दंड एक नागरिक दायित्व है जिसके लिए अपराधी को हुए नुकसान के लिए प्रभावित पक्ष को आनुपातिक मुआवजा देना होता है।"}},
{type:"mcq",diff:"medium",en:{q:"In cryptography, what primary security goals does a Digital Signature fulfill?",opts:["Confidentiality and Speed","Authentication, Data Integrity, and Non-repudiation","Compression and Routing","Hardware redundancy"],ans:1,exp:"A Digital Signature utilizes asymmetric cryptography to guarantee the authenticity of the sender, ensure the integrity of the message (verifying it hasn't been altered), and provide non-repudiation (the sender cannot deny signing the data)."},hi:{q:"क्रिप्टोग्राफी में, डिजिटल हस्ताक्षर (Digital Signature) किन प्राथमिक सुरक्षा लक्ष्यों को पूरा करता है?",opts:["गोपनीयता और गति","प्रमाणीकरण (Authentication), डेटा अखंडता (Data Integrity), और गैर-अस्वीकरण (Non-repudiation)","संपीड़न और रूटिंग","हार्डवेयर रिडंडेंसी"],ans:1,exp:"एक डिजिटल हस्ताक्षर प्रेषक की प्रामाणिकता की गारंटी देने, संदेश की अखंडता सुनिश्चित करने (यह सत्यापित करना कि इसे बदला नहीं गया है), और गैर-अस्वीकरण (प्रेषक डेटा पर हस्ताक्षर करने से इनकार नहीं कर सकता) प्रदान करने के लिए असममित क्रिप्टोग्राफी का उपयोग करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is a 'Botnet'?",opts:["A friendly robotic assistant","A network of private computers infected with malicious software and controlled as a group without the owners' knowledge","A new type of search engine","A protocol for secure emails"],ans:1,exp:"A Botnet (Robot Network) comprises hundreds or thousands of internet-connected devices (zombies) infected with malware. A remote attacker, known as a bot-herder, commands this vast network to execute coordinated campaigns like massive DDoS attacks or spam distribution."},hi:{q:"'बॉटनेट' (Botnet) क्या है?",opts:["एक अनुकूल रोबोटिक सहायक","दुर्भावनापूर्ण सॉफ़्टवेयर से संक्रमित निजी कंप्यूटरों का एक नेटवर्क जिन्हें मालिकों की जानकारी के बिना एक समूह के रूप में नियंत्रित किया जाता है","एक नए प्रकार का खोज इंजन","सुरक्षित ईमेल के लिए एक प्रोटोकॉल"],ans:1,exp:"एक बॉटनेट (रोबोट नेटवर्क) में मैलवेयर से संक्रमित सैकड़ों या हजारों इंटरनेट से जुड़े डिवाइस (ज़ॉम्बी) शामिल होते हैं। एक दूरस्थ हमलावर, जिसे बॉट-हर्डर कहा जाता है, इस विशाल नेटवर्क को बड़े पैमाने पर DDoS हमलों या स्पैम वितरण जैसे समन्वित अभियानों को निष्पादित करने का आदेश देता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following defines an 'Eavesdropping' attack?",opts:["Guessing a password repeatedly","Surreptitiously intercepting and reading confidential network communications in transit","Sending overwhelming traffic to a server","Encrypting files for ransom"],ans:1,exp:"Eavesdropping (or Sniffing) is a passive network attack where an unauthorized entity secretly intercepts, monitors, and captures data packets traversing a network. It is highly effective on unencrypted public Wi-Fi networks for harvesting plaintext credentials."},hi:{q:"निम्नलिखित में से कौन सा 'ईव्सड्रॉपिंग' (Eavesdropping - छिपकर बातें सुनना) हमले को परिभाषित करता है?",opts:["बार-बार पासवर्ड का अनुमान लगाना","पारगमन (transit) में गोपनीय नेटवर्क संचार को गुप्त रूप से इंटरसेप्ट करना और पढ़ना","सर्वर पर भारी ट्रैफ़िक भेजना","फिरौती के लिए फ़ाइलों को एन्क्रिप्ट करना"],ans:1,exp:"ईव्सड्रॉपिंग (या स्निफ़िंग) एक निष्क्रिय नेटवर्क हमला है जहाँ एक अनधिकृत इकाई गुप्त रूप से नेटवर्क से गुजरने वाले डेटा पैकेटों को रोकती है, निगरानी करती है और कैप्चर करती है। यह प्लेनटेक्स्ट क्रेडेंशियल्स की कटाई के लिए अनएन्क्रिप्टेड सार्वजनिक वाई-फाई नेटवर्क पर अत्यधिक प्रभावी है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the primary characteristic of a 'Rootkit'?",opts:["It displays advertisements","It acts as a firewall","It is a collection of tools designed to grant persistent, stealthy administrative access to a system while hiding its presence","It speeds up CPU performance"],ans:2,exp:"A Rootkit is highly sophisticated malware engineered to embed itself deeply into an operating system (often at the kernel level). It actively subverts OS functions to remain completely undetectable to standard antivirus software while maintaining root-level access for the attacker."},hi:{q:"'रूटकिट' (Rootkit) की प्राथमिक विशेषता क्या है?",opts:["यह विज्ञापन प्रदर्शित करता है","यह फ़ायरवॉल के रूप में कार्य करता है","यह उपकरणों का एक संग्रह है जिसे अपनी उपस्थिति छिपाते हुए सिस्टम को लगातार, गुप्त प्रशासनिक पहुँच (administrative access) प्रदान करने के लिए डिज़ाइन किया गया है","यह CPU प्रदर्शन को गति देता है"],ans:2,exp:"एक रूटकिट अत्यधिक परिष्कृत मैलवेयर है जिसे एक ऑपरेटिंग सिस्टम (अक्सर कर्नेल स्तर पर) में गहराई से एम्बेड करने के लिए इंजीनियर किया गया है। यह हमलावर के लिए रूट-स्तरीय पहुंच बनाए रखते हुए मानक एंटीवायरस सॉफ़्टवेयर के लिए पूरी तरह से ज्ञानी बने रहने के लिए ओएस कार्यों को सक्रिय रूप से नष्ट कर देता है।"}},
{type:"mcq",diff:"medium",en:{q:"In malicious software, what is a 'Logic Bomb'?",opts:["A hardware defect","A program that generates random numbers","Malicious code that lies dormant until triggered by a specific predefined condition or date","A program used to encrypt the entire internet"],ans:2,exp:"A Logic Bomb is a piece of malicious code intentionally inserted into software. It remains entirely dormant and undetected until a highly specific logical condition is met—such as a specific date, time, or system event—at which point it detonates and executes its payload."},hi:{q:"दुर्भावनापूर्ण सॉफ़्टवेयर में, 'लॉजिक बॉम्ब' (Logic Bomb) क्या है?",opts:["एक हार्डवेयर दोष","एक प्रोग्राम जो यादृच्छिक संख्याएं उत्पन्न करता है","दुर्भावनापूर्ण कोड जो किसी विशिष्ट पूर्व-निर्धारित स्थिति या तिथि द्वारा ट्रिगर होने तक निष्क्रिय (dormant) रहता है","पूरे इंटरनेट को एन्क्रिप्ट करने के लिए उपयोग किया जाने वाला एक प्रोग्राम"],ans:2,exp:"लॉजिक बम जानबूझकर सॉफ़्टवेयर में डाला गया दुर्भावनापूर्ण कोड का एक टुकड़ा है। यह पूरी तरह से निष्क्रिय और अनिर्धारित रहता है जब तक कि एक अत्यधिक विशिष्ट तार्किक स्थिति पूरी नहीं हो जाती-जैसे कोई विशिष्ट तिथि, समय या सिस्टम घटना-जिस बिंदु पर यह विस्फोट करता है और अपना पेलोड निष्पादित करता है।"}},
{type:"mcq",diff:"medium",en:{q:"In a Public Key Infrastructure (PKI), what is the core responsibility of a Certificate Authority (CA)?",opts:["To generate random IP addresses","To securely issue, sign, and revoke digital certificates binding public keys to specific identities","To install antivirus software on client PCs","To act as an email server"],ans:1,exp:"A Certificate Authority (CA) acts as the ultimate trusted third party in a PKI ecosystem. It cryptographically signs digital certificates, attesting that the public key contained within genuinely belongs to the subject (like a website), thereby establishing trust."},hi:{q:"पब्लिक की इंफ्रास्ट्रक्चर (PKI) में, प्रमाणपत्र प्राधिकरण (Certificate Authority - CA) की मुख्य जिम्मेदारी क्या है?",opts:["यादृच्छिक IP पते उत्पन्न करना","विशिष्ट पहचान के लिए सार्वजनिक कुंजियों को बाध्य करने वाले डिजिटल प्रमाणपत्रों को सुरक्षित रूप से जारी करना, हस्ताक्षर करना और रद्द करना","क्लाइंट पीसी पर एंटीवायरस सॉफ़्टवेयर स्थापित करना","ईमेल सर्वर के रूप में कार्य करना"],ans:1,exp:"एक प्रमाणपत्र प्राधिकरण (CA) PKI पारिस्थितिकी तंत्र में अंतिम विश्वसनीय तृतीय पक्ष के रूप में कार्य करता है। यह डिजिटल प्रमाणपत्रों पर क्रिप्टोग्राफ़िक रूप से हस्ताक्षर करता है, यह प्रमाणित करता है कि भीतर मौजूद सार्वजनिक कुंजी वास्तव में विषय (जैसे वेबसाइट) से संबंधित है, जिससे विश्वास स्थापित होता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the purpose of an Access Control List (ACL) in network security?",opts:["To compress network packets","To maintain a sequential list of authorized and unauthorized IP addresses, ports, or users regulating access to a resource","To boost Wi-Fi signal strength","To convert domain names to IP addresses"],ans:1,exp:"An Access Control List (ACL) is a sequential table of filtering rules deployed on routers and firewalls. It meticulously evaluates incoming and outgoing network traffic parameters (like source IP, destination IP, and port) to explicitly permit or deny packet transit."},hi:{q:"नेटवर्क सुरक्षा में एक्सेस कंट्रोल लिस्ट (ACL) का क्या उद्देश्य है?",opts:["नेटवर्क पैकेटों को संपीड़ित (compress) करना","किसी संसाधन तक पहुंच को विनियमित करने वाले अधिकृत और अनधिकृत IP पते, पोर्ट या उपयोगकर्ताओं की एक क्रमिक सूची बनाए रखना","वाई-फाई सिग्नल की शक्ति बढ़ाना","डोमेन नामों को IP पते में परिवर्तित करना"],ans:1,exp:"एक्सेस कंट्रोल लिस्ट (ACL) राउटर और फायरवॉल पर तैनात फ़िल्टरिंग नियमों की एक क्रमिक तालिका है। यह पैकेट पारगमन को स्पष्ट रूप से अनुमति देने या अस्वीकार करने के लिए आने वाले और जाने वाले नेटवर्क ट्रैफ़िक मापदंडों (जैसे स्रोत IP, गंतव्य IP और पोर्ट) का सावधानीपूर्वक मूल्यांकन करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What characterizes a 'Grey Hat Hacker'?",opts:["They exclusively steal money","They work completely legally as security analysts","They occasionally break laws or bypass authorization but generally lack malicious intent, sometimes notifying administrators of flaws","They are government spies"],ans:2,exp:"A Grey Hat Hacker occupies the moral center between Black and White hats. They may probe networks without explicit authorization (breaking laws), but instead of exploiting the discovered vulnerabilities for malicious gain, they typically report them to the owners, sometimes asking for a bounty."},hi:{q:"'ग्रे हैट हैकर' (Grey Hat Hacker) की क्या विशेषता है?",opts:["वे विशेष रूप से पैसे चुराते हैं","वे सुरक्षा विश्लेषक के रूप में पूरी तरह से कानूनी रूप से काम करते हैं","वे कभी-कभी कानून तोड़ते हैं या प्राधिकरण को बायपास करते हैं, लेकिन आम तौर पर उनमें दुर्भावनापूर्ण इरादे की कमी होती है, कभी-कभी प्रशासकों को खामियों के बारे में सूचित करते हैं","वे सरकारी जासूस हैं"],ans:2,exp:"एक ग्रे हैट हैकर ब्लैक और व्हाइट हैट्स के बीच नैतिक केंद्र पर कब्जा कर लेता है। वे स्पष्ट प्राधिकरण के बिना नेटवर्क की जांच कर सकते हैं (कानून तोड़ सकते हैं), लेकिन दुर्भावनापूर्ण लाभ के लिए खोजी गई कमजोरियों का फायदा उठाने के बजाय, वे आम तौर पर मालिकों को उनकी रिपोर्ट करते हैं, कभी-कभी इनाम की मांग करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which protocol currently provides the strongest security for a home Wi-Fi network?",opts:["WEP","WPA","WPA2/WPA3","MAC Filtering"],ans:2,exp:"WPA3 (and its highly prevalent predecessor WPA2) uses Advanced Encryption Standard (AES) combined with robust handshake protocols. These modern Wi-Fi Protected Access standards render older, deeply flawed protocols like WEP functionally obsolete against cryptographic attacks."},hi:{q:"कौन सा प्रोटोकॉल वर्तमान में होम वाई-फाई नेटवर्क के लिए सबसे मजबूत सुरक्षा प्रदान करता है?",opts:["WEP","WPA","WPA2/WPA3","मैक फ़िल्टरिंग (MAC Filtering)"],ans:2,exp:"WPA3 (और इसके अत्यधिक प्रचलित पूर्ववर्ती WPA2) मजबूत हैंडशेक प्रोटोकॉल के साथ उन्नत एन्क्रिप्शन स्टैंडर्ड (AES) का उपयोग करते हैं। ये आधुनिक वाई-फाई प्रोटेक्टेड एक्सेस मानक WEP जैसे पुराने, गहराई से त्रुटिपूर्ण प्रोटोकॉल को क्रिप्टोग्राफ़िक हमलों के खिलाफ कार्यात्मक रूप से अप्रचलित बना देते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"What differentiates 'Spear Phishing' from standard 'Phishing'?",opts:["Spear phishing uses physical mail","Spear phishing targets a highly specific individual or organization with personalized information, whereas standard phishing is generic and widespread","Spear phishing is completely legal","Spear phishing only occurs on mobile devices"],ans:1,exp:"While standard phishing uses a 'spray and pray' methodology sending generic emails to massive lists, Spear Phishing is highly targeted. Attackers perform reconnaissance on a specific individual to craft a personalized, convincing email, vastly increasing the success rate."},hi:{q:"'स्पीयर फिशिंग' (Spear Phishing) मानक 'फिशिंग' से कैसे अलग है?",opts:["स्पीयर फिशिंग भौतिक मेल का उपयोग करती है","स्पीयर फिशिंग व्यक्तिगत जानकारी के साथ किसी अत्यधिक विशिष्ट व्यक्ति या संगठन को लक्षित करती है, जबकि मानक फिशिंग सामान्य और व्यापक है","स्पीयर फिशिंग पूरी तरह से कानूनी है","स्पीयर फिशिंग केवल मोबाइल उपकरणों पर होती है"],ans:1,exp:"जबकि मानक फिशिंग बड़े पैमाने पर सूचियों में सामान्य ईमेल भेजने के लिए 'स्प्रे और प्रार्थना' (spray and pray) पद्धति का उपयोग करती है, स्पीयर फिशिंग अत्यधिक लक्षित होती है। हमलावर एक विशिष्ट व्यक्ति पर एक व्यक्तिगत, ठोस ईमेल तैयार करने के लिए टोह लेते हैं, जिससे सफलता दर काफी बढ़ जाती है।"}},
{type:"tf",diff:"medium",en:{q:"A computer worm requires a host file or explicit user action (like opening an attachment) to execute and spread across networks.",opts:["True","False"],ans:1,exp:"False. Unlike a traditional virus, a worm is a completely standalone malicious program. It actively searches for system vulnerabilities to self-replicate and spread horizontally across network connections without requiring any host file or human intervention."},hi:{q:"एक कंप्यूटर वर्म (Worm) को निष्पादित करने और नेटवर्क में फैलने के लिए एक होस्ट फ़ाइल या स्पष्ट उपयोगकर्ता कार्रवाई (जैसे एक अनुलग्नक खोलना) की आवश्यकता होती है।",opts:["सही","गलत"],ans:1,exp:"गलत। पारंपरिक वायरस के विपरीत, एक वर्म पूरी तरह से स्टैंडअलोन दुर्भावनापूर्ण प्रोग्राम है। यह किसी भी होस्ट फ़ाइल या मानवीय हस्तक्षेप की आवश्यकता के बिना नेटवर्क कनेक्शन पर क्षैतिज रूप से फैलने और खुद को दोहराने के लिए सिस्टम की कमजोरियों को सक्रिय रूप से खोजता है।"}},
{type:"tf",diff:"medium",en:{q:"Section 66F of the Information Technology Act, 2000 deals specifically with the severe offense of Cyber Terrorism.",opts:["True","False"],ans:0,exp:"True. Section 66F was introduced in the 2008 amendments to the IT Act. It strictly defines and outlines punishments for Cyber Terrorism, stipulating that perpetrators threatening the unity, integrity, or security of India face a maximum penalty of life imprisonment."},hi:{q:"सूचना प्रौद्योगिकी अधिनियम, 2000 की धारा 66F विशेष रूप से साइबर आतंकवाद (Cyber Terrorism) के गंभीर अपराध से संबंधित है।",opts:["सही","गलत"],ans:0,exp:"सही। धारा 66F को IT अधिनियम में 2008 के संशोधनों में पेश किया गया था। यह साइबर आतंकवाद के लिए दंड को कड़ाई से परिभाषित और रेखांकित करता है, जिसमें यह निर्धारित किया गया है कि भारत की एकता, अखंडता या सुरक्षा को खतरे में डालने वाले अपराधियों को अधिकतम आजीवन कारावास की सजा का सामना करना पड़ता है।"}},
{type:"mcq",diff:"hard",en:{q:"According to Section 65 of the IT Act, 2000, what is the exact maximum penalty for intentionally tampering with computer source documents?",opts:["Up to 1 year imprisonment or Rs. 1 Lakh fine","Up to 3 years imprisonment or Rs. 2 Lakh fine, or both","Up to 5 years imprisonment or Rs. 5 Lakh fine","Life imprisonment"],ans:1,exp:"Section 65 of the IT Act strictly addresses the offense of knowingly or intentionally concealing, destroying, or altering computer source code (like program logic) required to be maintained by law. The mandated punishment is imprisonment extending up to 3 years, a fine up to Rs. 2 Lakh, or both."},hi:{q:"IT अधिनियम, 2000 की धारा 65 के अनुसार, जानबूझकर कंप्यूटर स्रोत दस्तावेजों (computer source documents) के साथ छेड़छाड़ करने के लिए अधिकतम जुर्माना क्या है?",opts:["1 साल तक की जेल या 1 लाख रुपये का जुर्माना","3 साल तक की जेल या 2 लाख रुपये का जुर्माना, या दोनों","5 साल तक की जेल या 5 लाख रुपये का जुर्माना","आजीवन कारावास"],ans:1,exp:"आईटी अधिनियम की धारा 65 कड़ाई से कंप्यूटर स्रोत कोड (जैसे प्रोग्राम लॉजिक) को जानबूझकर छिपाने, नष्ट करने या बदलने के अपराध को संबोधित करती है जिसे कानून द्वारा बनाए रखा जाना आवश्यक है। अनिवार्य सजा 3 साल तक की कैद, 2 लाख रुपये तक का जुर्माना या दोनों है।"}},
{type:"mcq",diff:"hard",en:{q:"Under Section 66C of the IT Act, which deals with Identity Theft, what constitutes the prescribed punishment for fraudulent use of another person's electronic signature or password?",opts:["Imprisonment up to 1 year or Rs. 50,000 fine","Imprisonment up to 3 years and a fine up to Rs. 1 Lakh","Imprisonment up to 7 years without fine","Only a warning for the first offense"],ans:1,exp:"Section 66C penalizes identity theft. Whoever, fraudulently or dishonestly, makes use of the electronic signature, password, or any other unique identification feature of any other person, is punishable with imprisonment for up to 3 years and a fine that may extend to Rs. 1 Lakh."},hi:{q:"IT अधिनियम की धारा 66C के तहत, जो पहचान की चोरी (Identity Theft) से संबंधित है, किसी अन्य व्यक्ति के इलेक्ट्रॉनिक हस्ताक्षर या पासवर्ड के कपटपूर्ण उपयोग के लिए निर्धारित दंड क्या है?",opts:["1 साल तक की कैद या 50,000 रुपये का जुर्माना","3 साल तक की कैद और 1 लाख रुपये तक का जुर्माना","बिना जुर्माने के 7 साल तक की कैद","पहले अपराध के लिए केवल एक चेतावनी"],ans:1,exp:"धारा 66C पहचान की चोरी को दंडित करती है। जो कोई भी, कपटपूर्ण या बेईमानी से, किसी अन्य व्यक्ति के इलेक्ट्रॉनिक हस्ताक्षर, पासवर्ड, या किसी अन्य अद्वितीय पहचान सुविधा का उपयोग करता है, वह 3 साल तक के कारावास और जुर्माने से दंडनीय है जो 1 लाख रुपये तक हो सकता है।"}},
{type:"mcq",diff:"hard",en:{q:"In Directory Services, what is the default TCP port utilized by secure LDAP (LDAPS) to encrypt query traffic?",opts:["Port 389","Port 80","Port 636","Port 22"],ans:2,exp:"While standard, unencrypted Lightweight Directory Access Protocol (LDAP) operates over TCP port 389, LDAPS (LDAP over SSL/TLS) encrypts the directory binding and querying session, utilizing TCP port 636 natively to ensure credential confidentiality."},hi:{q:"डायरेक्टरी सर्विसेज में, क्वेरी ट्रैफ़िक को एन्क्रिप्ट करने के लिए सुरक्षित LDAP (LDAPS) द्वारा उपयोग किया जाने वाला डिफ़ॉल्ट TCP पोर्ट क्या है?",opts:["पोर्ट 389","पोर्ट 80","पोर्ट 636","पोर्ट 22"],ans:2,exp:"जबकि मानक, अनएन्क्रिप्टेड लाइटवेट डायरेक्टरी एक्सेस प्रोटोकॉल (LDAP) टीसीपी पोर्ट 389 पर काम करता है, LDAPS (LDAP ओवर SSL/TLS) डायरेक्टरी बाइंडिंग और क्वेरी सत्र को एन्क्रिप्ट करता है, जो क्रेडेंशियल गोपनीयता सुनिश्चित करने के लिए मूल रूप से TCP पोर्ट 636 का उपयोग करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which access control model relies entirely on the system's operating system to restrict resource access based on security labels and clearances, completely preventing the data owner from altering permissions?",opts:["Discretionary Access Control (DAC)","Mandatory Access Control (MAC)","Role-Based Access Control (RBAC)","Attribute-Based Access Control (ABAC)"],ans:1,exp:"Mandatory Access Control (MAC) is an extremely rigid access model heavily utilized in military environments. The system administrator strictly assigns hierarchical security labels (e.g., Top Secret) to data objects. The actual creator or owner of the file cannot override or modify these overarching system access policies."},hi:{q:"कौन सा एक्सेस कंट्रोल मॉडल सुरक्षा लेबलों (security labels) और क्लीयरेंस के आधार पर संसाधन पहुंच को प्रतिबंधित करने के लिए पूरी तरह से सिस्टम के ऑपरेटिंग सिस्टम पर निर्भर करता है, जो डेटा मालिक को अनुमतियों को बदलने से पूरी तरह से रोकता है?",opts:["विवेकाधीन एक्सेस कंट्रोल (DAC)","अनिवार्य एक्सेस कंट्रोल (MAC / Mandatory Access Control)","भूमिका-आधारित एक्सेस कंट्रोल (RBAC)","एट्रिब्यूट-आधारित एक्सेस कंट्रोल (ABAC)"],ans:1,exp:"अनिवार्य एक्सेस कंट्रोल (MAC) एक अत्यंत कठोर एक्सेस मॉडल है जिसका सैन्य वातावरण में भारी उपयोग किया जाता है। सिस्टम एडमिनिस्ट्रेटर डेटा ऑब्जेक्ट्स को पदानुक्रमित सुरक्षा लेबल (उदा., टॉप सीक्रेट) सख्ती से निर्दिष्ट करता है। फ़ाइल का वास्तविक निर्माता या स्वामी इन अतिव्यापी सिस्टम एक्सेस नीतियों को ओवरराइड या संशोधित नहीं कर सकता है।"}},
{type:"mcq",diff:"hard",en:{q:"In contrast to MAC, how does Discretionary Access Control (DAC) function regarding file permissions?",opts:["It forces all users to have the same access level","It assigns access based strictly on a user's job title","It allows the creator or owner of an object to exercise full discretion in defining which subjects can access it","It relies on biometric scanning for all file access"],ans:2,exp:"In a Discretionary Access Control (DAC) environment (like standard Windows or Linux file systems), the original owner of a file or directory has absolute discretion to grant or revoke specific access permissions (read, write, execute) to any other user or group at their will."},hi:{q:"MAC के विपरीत, फ़ाइल अनुमतियों के संबंध में विवेकाधीन एक्सेस कंट्रोल (DAC) कैसे कार्य करता है?",opts:["यह सभी उपयोगकर्ताओं को समान पहुंच स्तर (access level) रखने के लिए मजबूर करता है","यह विशुद्ध रूप से उपयोगकर्ता के जॉब टाइटल के आधार पर एक्सेस निर्दिष्ट करता है","यह किसी ऑब्जेक्ट के निर्माता या स्वामी को यह परिभाषित करने में पूर्ण विवेक का प्रयोग करने की अनुमति देता है कि कौन से विषय (subjects) उस तक पहुंच सकते हैं","यह सभी फ़ाइल एक्सेस के लिए बायोमेट्रिक स्कैनिंग पर निर्भर करता है"],ans:2,exp:"विवेकाधीन एक्सेस कंट्रोल (DAC) वातावरण (जैसे मानक विंडोज या लिनक्स फाइल सिस्टम) में, किसी फाइल या डायरेक्टरी के मूल मालिक के पास अपनी इच्छा से किसी अन्य उपयोगकर्ता या समूह को विशिष्ट एक्सेस अनुमतियां (पढ़ना, लिखना, निष्पादित करना) देने या रद्द करने का पूर्ण विवेक (discretion) होता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which of the following strictly enumerates the standardized key lengths utilized by the Advanced Encryption Standard (AES) algorithm?",opts:["64, 128, and 256 bits","128, 192, and 256 bits","256, 512, and 1024 bits","56, 112, and 168 bits"],ans:1,exp:"The Advanced Encryption Standard (AES), established by NIST, is a symmetric block cipher mathematically designed to process 128-bit data blocks utilizing cryptographic keys with precise lengths of exactly 128, 192, or 256 bits, dictating the number of internal transformation rounds."},hi:{q:"निम्नलिखित में से कौन उन्नत एन्क्रिप्शन स्टैंडर्ड (AES) एल्गोरिथम द्वारा उपयोग की जाने वाली मानकीकृत कुंजी लंबाई (key lengths) को सख्ती से गिनाता है?",opts:["64, 128, और 256 बिट्स","128, 192, और 256 बिट्स","256, 512, और 1024 बिट्स","56, 112, और 168 बिट्स"],ans:1,exp:"NIST द्वारा स्थापित उन्नत एन्क्रिप्शन स्टैंडर्ड (AES), एक सममित ब्लॉक सिफर है जिसे गणितीय रूप से 128-बिट डेटा ब्लॉक को संसाधित करने के लिए डिज़ाइन किया गया है जो ठीक 128, 192 या 256 बिट्स की सटीक लंबाई के साथ क्रिप्टोग्राफ़िक कुंजियों का उपयोग करता है, जो आंतरिक परिवर्तन दौरों की संख्या तय करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which cryptographic hashing algorithm fundamentally guarantees a fixed, irreversible digest output length of precisely 256 bits?",opts:["MD5","SHA-1","SHA-256","RC4"],ans:2,exp:"SHA-256 (Secure Hash Algorithm 256-bit) is a highly secure member of the SHA-2 cryptographic hash function family. Regardless of whether the input is a single character or a 10 GB file, the mathematical processing ensures the resulting collision-resistant hash digest is exactly 256 bits long."},hi:{q:"कौन सा क्रिप्टोग्राफ़िक हैशिंग एल्गोरिदम मौलिक रूप से ठीक 256 बिट्स की एक निश्चित, अपरिवर्तनीय डाइजेस्ट आउटपुट लंबाई की गारंटी देता है?",opts:["MD5","SHA-1","SHA-256","RC4"],ans:2,exp:"SHA-256 (सिक्योर हैश एल्गोरिथम 256-बिट) SHA-2 क्रिप्टोग्राफ़िक हैश फ़ंक्शन परिवार का एक अत्यधिक सुरक्षित सदस्य है। इनपुट चाहे एक सिंगल कैरेक्टर हो या 10 जीबी फाइल, गणितीय प्रसंस्करण यह सुनिश्चित करता है कि परिणामी टक्कर-प्रतिरोधी (collision-resistant) हैश डाइजेस्ट बिल्कुल 256 बिट लंबा है।"}},
{type:"mcq",diff:"hard",en:{q:"In Web Application Security, what specific mechanism defines a Cross-Site Scripting (XSS) attack?",opts:["Exploiting weak database structures to extract SQL tables","Injecting malicious, executable client-side scripts into web pages viewed by other innocent users","Flooding the web server with fake HTTP requests","Guessing administrator passwords rapidly"],ans:1,exp:"Cross-Site Scripting (XSS) is a severe vulnerability where web applications fail to sanitize input. Attackers inject executable scripts (typically JavaScript) into trusted sites. When an innocent victim browses the affected page, the malicious script executes in their browser, potentially hijacking active sessions."},hi:{q:"वेब एप्लिकेशन सुरक्षा में, कौन सा विशिष्ट तंत्र क्रॉस-साइट स्क्रिप्टिंग (XSS) हमले को परिभाषित करता है?",opts:["SQL तालिकाओं को निकालने के लिए कमजोर डेटाबेस संरचनाओं का शोषण करना","अन्य निर्दोष उपयोगकर्ताओं द्वारा देखे गए वेब पेजों में दुर्भावनापूर्ण, निष्पादन योग्य (executable) क्लाइंट-साइड स्क्रिप्ट इंजेक्ट करना","फर्जी HTTP अनुरोधों के साथ वेब सर्वर को अभिभूत करना","प्रशासक के पासवर्ड का तेजी से अनुमान लगाना"],ans:1,exp:"क्रॉस-साइट स्क्रिप्टिंग (XSS) एक गंभीर भेद्यता है जहां वेब एप्लिकेशन इनपुट को साफ करने (sanitize) में विफल रहते हैं। हमलावर विश्वसनीय साइटों में निष्पादन योग्य स्क्रिप्ट (आमतौर पर जावास्क्रिप्ट) इंजेक्ट करते हैं। जब कोई निर्दोष शिकार प्रभावित पृष्ठ को ब्राउज़ करता है, तो दुर्भावनापूर्ण स्क्रिप्ट उनके ब्राउज़र में निष्पादित होती है, जो संभावित रूप से सक्रिय सत्रों का अपहरण करती है।"}},
{type:"mcq",diff:"hard",en:{q:"Which highly effective programming methodology is globally recognized as the primary defense mechanism against SQL Injection vulnerabilities?",opts:["Client-side JavaScript validation","Prepared Statements (Parameterized Queries)","Upgrading the server RAM","Using shorter SQL syntax"],ans:1,exp:"Prepared Statements (Parameterized Queries) force the database to treat user input purely as literal data values rather than executable code. Because the SQL engine compiles the query structure independently of the dynamic input, malicious payload injections are rendered entirely ineffective."},hi:{q:"एसक्यूएल (SQL) इंजेक्शन कमजोरियों के खिलाफ प्राथमिक रक्षा तंत्र के रूप में किस अत्यधिक प्रभावी प्रोग्रामिंग पद्धति को विश्व स्तर पर मान्यता प्राप्त है?",opts:["क्लाइंट-साइड जावास्क्रिप्ट सत्यापन","तैयार कथन (Prepared Statements / Parameterized Queries)","सर्वर की RAM को अपग्रेड करना","छोटे SQL सिंटैक्स का उपयोग करना"],ans:1,exp:"प्रेपेयर्ड स्टेटमेंट्स डेटाबेस को उपयोगकर्ता के इनपुट को निष्पादन योग्य (executable) कोड के बजाय पूरी तरह से शाब्दिक डेटा मानों के रूप में मानने के लिए मजबूर करते हैं। चूँकि SQL इंजन गतिशील इनपुट से स्वतंत्र रूप से क्वेरी संरचना को संकलित करता है, इसलिए दुर्भावनापूर्ण पेलोड इंजेक्शन पूरी तरह से अप्रभावी हो जाते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"What characterizes the cryptographic technique known as 'Steganography'?",opts:["Encrypting text using a public key","Digitally signing an email","The practice of concealing secret data or messages entirely within ordinary, non-secret files or images","Cracking passwords using supercomputers"],ans:2,exp:"While standard cryptography makes the message unreadable, Steganography hides the very existence of the communication. It leverages algorithms to seamlessly embed secret ciphertext payload bits into the lowest significant bits of mundane carrier files (like JPEG images or MP3 audio)."},hi:{q:"'स्टेग्नोग्राफ़ी' (Steganography) नामक क्रिप्टोग्राफ़िक तकनीक की क्या विशेषता है?",opts:["सार्वजनिक कुंजी (public key) का उपयोग करके पाठ को एन्क्रिप्ट करना","ईमेल पर डिजिटल हस्ताक्षर करना","गुप्त डेटा या संदेशों को पूरी तरह से साधारण, गैर-गुप्त फ़ाइलों या छवियों के भीतर छिपाने की प्रथा","सुपरकंप्यूटर का उपयोग करके पासवर्ड क्रैक करना"],ans:2,exp:"जबकि मानक क्रिप्टोग्राफी संदेश को अपठनीय बना देती है, स्टेग्नोग्राफ़ी संचार के अस्तित्व को ही छिपा देती है। यह गुप्त सिफरटेक्स्ट पेलोड बिट्स को सांसारिक वाहक फ़ाइलों (जैसे JPEG छवियों या MP3 ऑडियो) के सबसे कम महत्वपूर्ण बिट्स में मूल रूप से एम्बेड करने के लिए एल्गोरिदम का लाभ उठाता है।"}},
{type:"mcq",diff:"hard",en:{q:"Within the IPsec protocol suite suite designed to secure network communications, which two distinct operational modes are utilized?",opts:["Active and Passive modes","Transport mode and Tunnel mode","Encryption and Decryption modes","Stateful and Stateless modes"],ans:1,exp:"IPsec operates in two distinct modes. 'Transport mode' exclusively encrypts the IP packet payload (data), leaving the original IP header intact for end-to-end communication. 'Tunnel mode' encrypts the entire original IP packet and generates a completely new outer IP header, heavily utilized in Site-to-Site VPNs."},hi:{q:"नेटवर्क संचार को सुरक्षित करने के लिए डिज़ाइन किए गए IPsec प्रोटोकॉल सूट के भीतर, किन दो अलग-अलग परिचालन मोड (operational modes) का उपयोग किया जाता है?",opts:["सक्रिय और निष्क्रिय (Active and Passive) मोड","ट्रांसपोर्ट मोड और टनल मोड (Transport mode and Tunnel mode)","एन्क्रिप्शन और डिक्रिप्शन मोड","स्टेटफुल और स्टेटलेस मोड"],ans:1,exp:"IPsec दो अलग-अलग मोड में काम करता है। 'ट्रांसपोर्ट मोड' विशेष रूप से आईपी पैकेट पेलोड (डेटा) को एन्क्रिप्ट करता है, एंड-टू-एंड संचार के लिए मूल आईपी हेडर को बरकरार रखता है। 'टनल मोड' संपूर्ण मूल आईपी पैकेट को एन्क्रिप्ट करता है और साइट-टू-साइट वीपीएन में भारी उपयोग किए जाने वाले एक पूरी तरह से नया बाहरी आईपी हेडर उत्पन्न करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which ITU-T foundational standard fundamentally defines the logical information model and architectural structure of Directory Services (like LDAP)?",opts:["IEEE 802.11","X.500","IPv6","RFC 1918"],ans:1,exp:"The X.500 standard, developed by the ITU-T, established the comprehensive architectural framework for global directory services. It introduced the concept of the Directory Information Tree (DIT) and distinguished names. LDAP was actually engineered as a lightweight, TCP/IP-friendly subset of the complex X.500 protocol."},hi:{q:"कौन सा ITU-T मूलभूत मानक मौलिक रूप से निर्देशिका सेवाओं (Directory Services - जैसे LDAP) के तार्किक सूचना मॉडल और वास्तुशिल्प संरचना को परिभाषित करता है?",opts:["IEEE 802.11","X.500","IPv6","RFC 1918"],ans:1,exp:"ITU-T द्वारा विकसित X.500 मानक ने वैश्विक निर्देशिका सेवाओं के लिए व्यापक वास्तुशिल्प ढांचा (architectural framework) स्थापित किया। इसने डायरेक्टरी इंफॉर्मेशन ट्री (DIT) और विशिष्ट नामों की अवधारणा पेश की। LDAP को वास्तव में जटिल X.500 प्रोटोकॉल के लाइटवेट, TCP/IP-अनुकूल सबसेट के रूप में इंजीनियर किया गया था।"}},
{type:"mcq",diff:"hard",en:{q:"According to Section 66E of the Information Technology Act, 2000, what is the prescribed penalty for intentionally violating the privacy of an individual by capturing or transmitting images of their private areas without consent?",opts:["Imprisonment up to 1 year","Imprisonment up to 3 years or a fine not exceeding Rs. 2 Lakh, or both","Fine of Rs. 10,000 only","Imprisonment up to 7 years"],ans:1,exp:"Section 66E strictly protects personal privacy. It dictates that whoever intentionally captures, publishes, or transmits the image of a private area of any person without their explicit consent faces severe legal consequences, specifically imprisonment extending to 3 years or a fine up to Rs. 2 Lakh, or both."},hi:{q:"सूचना प्रौद्योगिकी अधिनियम, 2000 की धारा 66E के अनुसार, बिना सहमति के किसी व्यक्ति के निजी अंगों की तस्वीरें खींचकर या प्रसारित करके जानबूझकर उसकी निजता का उल्लंघन करने के लिए निर्धारित दंड क्या है?",opts:["1 साल तक की जेल","3 साल तक की जेल या जुर्माना जो 2 लाख रुपये से अधिक न हो, या दोनों","केवल 10,000 रुपये का जुर्माना","7 साल तक की जेल"],ans:1,exp:"धारा 66E व्यक्तिगत गोपनीयता की कड़ाई से रक्षा करती है। यह निर्धारित करता है कि जो कोई भी किसी व्यक्ति की स्पष्ट सहमति के बिना उसके निजी क्षेत्र की छवि को जानबूझकर पकड़ता है, प्रकाशित करता है या प्रसारित करता है, उसे गंभीर कानूनी परिणामों का सामना करना पड़ता है, विशेष रूप से 3 साल तक की कैद या 2 लाख रुपये तक का जुर्माना, या दोनों।"}},
{type:"mcq",diff:"hard",en:{q:"In Network Security architecture, what is a 'Honeypot'?",opts:["A secure folder for storing sensitive passwords","A decoy system or network intentionally engineered to mimic a vulnerable target to attract, detect, and study malicious attackers","A high-speed router","An automated backup server"],ans:1,exp:"A Honeypot is an elaborate defensive decoy. Security teams deploy it to simulate valuable network assets or flawed servers. When an attacker probes or compromises the honeypot, administrators silently gather critical intelligence regarding the attacker's methodologies, IPs, and zero-day exploits without jeopardizing production systems."},hi:{q:"नेटवर्क सुरक्षा आर्किटेक्चर में, 'हनीपॉट' (Honeypot) क्या है?",opts:["संवेदनशील पासवर्ड संग्रहीत करने के लिए एक सुरक्षित फ़ोल्डर","दुर्भावनापूर्ण हमलावरों को आकर्षित करने, पता लगाने और उनका अध्ययन करने के लिए एक कमजोर लक्ष्य की नकल करने के लिए जानबूझकर इंजीनियर किया गया एक डिकॉय (प्रलोभन) सिस्टम या नेटवर्क","एक हाई-स्पीड राउटर","एक स्वचालित बैकअप सर्वर"],ans:1,exp:"हनीपॉट एक विस्तृत रक्षात्मक डिकॉय (प्रलोभन) है। सुरक्षा दल इसे मूल्यवान नेटवर्क संपत्तियों या दोषपूर्ण सर्वरों का अनुकरण करने के लिए तैनात करते हैं। जब कोई हमलावर हनीपॉट की जांच करता है या उससे समझौता करता है, तो व्यवस्थापक उत्पादन प्रणालियों को खतरे में डाले बिना हमलावर की कार्यप्रणाली, आईपी और शून्य-दिन के कारनामों के बारे में चुपचाप महत्वपूर्ण खुफिया जानकारी एकत्र करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"In Cyber Forensics, the 'Order of Volatility' mandates the sequence in which digital evidence must be collected. Which component must be preserved FIRST due to its extreme volatility?",opts:["The Hard Disk Drive","Archival Backup Tapes","CPU Registers and Cache Memory","Random Access Memory (RAM)"],ans:2,exp:"The Order of Volatility is a foundational forensic doctrine. Evidence must be collected starting from the most fragile state. CPU Registers and Cache vanish the instant power drops or processing shifts. Following this, RAM is captured, followed by Network States, then Disk Drives, and finally physical archival media."},hi:{q:"साइबर फोरेंसिक में, 'ऑर्डर ऑफ वोलैटिलिटी' (Order of Volatility) वह क्रम अनिवार्य करता है जिसमें डिजिटल साक्ष्य एकत्र किए जाने चाहिए। अत्यधिक अस्थिरता (volatility) के कारण किस घटक को पहले सुरक्षित रखा जाना चाहिए?",opts:["हार्ड डिस्क ड्राइव","आर्काइवल बैकअप टेप","CPU रजिस्टर और कैश मेमोरी","रैंडम एक्सेस मेमोरी (RAM)"],ans:2,exp:"ऑर्डर ऑफ वोलैटिलिटी एक मूलभूत फोरेंसिक सिद्धांत है। सबसे नाजुक स्थिति से शुरू करके साक्ष्य एकत्र किए जाने चाहिए। शक्ति कम होने या प्रसंस्करण शिफ्ट होने पर CPU रजिस्टर और कैश तुरंत गायब हो जाते हैं। इसके बाद, RAM को कैप्चर किया जाता है, उसके बाद नेटवर्क स्टेट्स, फिर डिस्क ड्राइव, और अंत में भौतिक आर्काइवल मीडिया।"}},
{type:"mcq",diff:"hard",en:{q:"Which distinct characteristic differentiates a 'Metamorphic' virus from a 'Polymorphic' virus?",opts:["Metamorphic viruses completely rewrite their own underlying code in every iteration, whereas Polymorphic viruses only change their decryption routine and signature","Metamorphic viruses only infect Linux systems","Polymorphic viruses cannot be detected by any antivirus","Metamorphic viruses are physically harmful to hard drives"],ans:0,exp:"A Polymorphic virus uses a mutating decryption engine to alter its appearance while the core malicious code remains identical. Conversely, a Metamorphic virus is significantly more complex; it translates, edits, and entirely rewrites its own executable code structurally with each infection, frustrating signature-based detection mechanisms."},hi:{q:"कौन सी विशिष्ट विशेषता 'मेटामोर्फिक' (Metamorphic) वायरस को 'पॉलीमॉर्फिक' (Polymorphic) वायरस से अलग करती है?",opts:["मेटामोर्फिक वायरस हर पुनरावृत्ति में अपने स्वयं के अंतर्निहित कोड को पूरी तरह से फिर से लिखते हैं, जबकि पॉलीमॉर्फिक वायरस केवल अपनी डिक्रिप्शन रूटीन और हस्ताक्षर बदलते हैं","मेटामोर्फिक वायरस केवल लिनक्स सिस्टम को संक्रमित करते हैं","पॉलीमॉर्फिक वायरस का पता किसी भी एंटीवायरस द्वारा नहीं लगाया जा सकता है","मेटामोर्फिक वायरस भौतिक रूप से हार्ड ड्राइव के लिए हानिकारक हैं"],ans:0,exp:"एक पॉलीमॉर्फिक वायरस अपनी उपस्थिति को बदलने के लिए एक उत्परिवर्तन (mutating) डिक्रिप्शन इंजन का उपयोग करता है जबकि मुख्य दुर्भावनापूर्ण कोड समान रहता है। इसके विपरीत, एक मेटामोर्फिक वायरस काफी अधिक जटिल है; यह प्रत्येक संक्रमण के साथ अपने स्वयं के निष्पादन योग्य कोड का अनुवाद, संपादन और पूरी तरह से संरचनात्मक रूप से फिर से लिखता है, जो सिग्नेचर-आधारित पहचान तंत्र को निराश करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In modern Antivirus engines, what does 'Heuristic Analysis' fundamentally achieve?",opts:["It detects known viruses by matching exact hash signatures","It detects entirely new, unknown malware by analyzing the suspicious behavior or structural anomalies of a program executing in a sandbox","It formats the hard drive automatically","It encrypts files to prevent infections"],ans:1,exp:"Unlike signature-based detection which relies on a database of known hashes, Heuristic Analysis is proactive. The antivirus executes the file in a secure sandbox, monitoring for malicious intents (like attempting to modify the registry or hooking system processes) to detect zero-day malware before signatures are authored."},hi:{q:"आधुनिक एंटीवायरस इंजनों में, 'अनुमानी विश्लेषण' (Heuristic Analysis) मौलिक रूप से क्या प्राप्त करता है?",opts:["यह सटीक हैश हस्ताक्षरों का मिलान करके ज्ञात वायरस का पता लगाता है","यह सैंडबॉक्स में निष्पादित एक प्रोग्राम के संदिग्ध व्यवहार या संरचनात्मक विसंगतियों का विश्लेषण करके पूरी तरह से नए, अज्ञात मैलवेयर का पता लगाता है","यह हार्ड ड्राइव को स्वचालित रूप से प्रारूपित (format) करता है","यह संक्रमण को रोकने के लिए फ़ाइलों को एन्क्रिप्ट करता है"],ans:1,exp:"हस्ताक्षर-आधारित पहचान के विपरीत जो ज्ञात हैश के डेटाबेस पर निर्भर करता है, अनुमानी (Heuristic) विश्लेषण सक्रिय है। एंटीवायरस फ़ाइल को सुरक्षित सैंडबॉक्स में निष्पादित करता है, दुर्भावनापूर्ण इरादों की निगरानी करता है (जैसे कि रजिस्ट्री को संशोधित करने का प्रयास करना) ताकि हस्ताक्षर लिखे जाने से पहले जीरो-डे मैलवेयर का पता लगाया जा सके।"}},
{type:"mcq",diff:"hard",en:{q:"In what specific year underwent the Information Technology Act, 2000 a major, comprehensive amendment to introduce stringent provisions addressing Cyber Terrorism and Data Privacy?",opts:["2004","2006","2008","2012"],ans:2,exp:"The IT Act, 2000 underwent a massive overhaul via the Information Technology (Amendment) Act, 2008 (which received presidential assent in 2009). This critical amendment inserted extensive sections like 43A (data protection), 66A to 66F (addressing identity theft, voyeurism, and cyber terrorism)."},hi:{q:"किस विशिष्ट वर्ष में सूचना प्रौद्योगिकी अधिनियम, 2000 में साइबर आतंकवाद और डेटा गोपनीयता को संबोधित करने वाले कड़े प्रावधानों को पेश करने के लिए एक बड़ा, व्यापक संशोधन किया गया था?",opts:["2004","2006","2008","2012"],ans:2,exp:"आईटी अधिनियम, 2000 को सूचना प्रौद्योगिकी (संशोधन) अधिनियम, 2008 के माध्यम से एक बड़े पैमाने पर बदलाव से गुजरना पड़ा। इस महत्वपूर्ण संशोधन ने 43A (डेटा सुरक्षा), 66A से 66F (पहचान की चोरी, दृश्यता और साइबर आतंकवाद को संबोधित करते हुए) जैसे व्यापक वर्गों को सम्मिलित किया।"}},
{type:"mcq",diff:"hard",en:{q:"What unique legal obligation does Section 43A of the amended IT Act impose on 'Body Corporates' (commercial organizations) operating in India?",opts:["To register all employees with the government","To implement reasonable security practices to protect sensitive personal data, failure of which mandates the payment of heavy compensation to victims","To pay a cyber tax annually","To use only government-approved encryption"],ans:1,exp:"Section 43A makes corporate entities strictly liable. If a body corporate handling sensitive personal data or information is negligent in implementing and maintaining reasonable security practices and procedures, causing wrongful loss or wrongful gain, they must pay proportional compensation to the affected persons."},hi:{q:"संशोधित IT अधिनियम की धारा 43A भारत में काम करने वाले 'बॉडी कॉरपोरेट्स' (commercial organizations) पर क्या अद्वितीय कानूनी दायित्व लगाती है?",opts:["सभी कर्मचारियों को सरकार के साथ पंजीकृत करने के लिए","संवेदनशील व्यक्तिगत डेटा की सुरक्षा के लिए उचित सुरक्षा प्रथाओं को लागू करने के लिए, जिसकी विफलता पीड़ितों को भारी मुआवजे के भुगतान को अनिवार्य करती है","प्रतिवर्ष साइबर कर (cyber tax) का भुगतान करने के लिए","केवल सरकार द्वारा अनुमोदित एन्क्रिप्शन का उपयोग करने के लिए"],ans:1,exp:"धारा 43A कॉर्पोरेट संस्थाओं को सख्ती से उत्तरदायी बनाती है। यदि संवेदनशील व्यक्तिगत डेटा को संभालने वाला एक निकाय कॉर्पोरेट उचित सुरक्षा प्रथाओं को लागू करने और बनाए रखने में लापरवाही करता है, जिससे गलत नुकसान होता है, तो उन्हें प्रभावित व्यक्तियों को आनुपातिक मुआवजा देना होगा।"}},
{type:"mcq",diff:"hard",en:{q:"What tactical difference exists between a 'Dictionary Attack' and a 'Brute Force Attack' when attempting to compromise cryptographic passwords?",opts:["A dictionary attack uses a predetermined list of common words and phrases, while a brute force attack exhaustively tries every possible mathematical combination of characters","Brute force is significantly faster and more targeted than a dictionary attack","A dictionary attack only works on Linux servers","Brute force attacks target firewalls, dictionary attacks target routers"],ans:0,exp:"A Dictionary Attack is optimized; it hashes a massive file of known words, leaked passwords, and patterns, testing them against the target hash. A Brute Force attack is fundamentally exhaustive, systematically generating and hashing every single sequential permutation of characters until a match is found."},hi:{q:"क्रिप्टोग्राफ़िक पासवर्ड से समझौता करने का प्रयास करते समय 'डिक्शनरी अटैक' और 'ब्रूट फ़ोर्स अटैक' के बीच क्या सामरिक (tactical) अंतर मौजूद है?",opts:["डिक्शनरी अटैक सामान्य शब्दों और वाक्यांशों की पूर्व निर्धारित सूची का उपयोग करता है, जबकि ब्रूट फ़ोर्स अटैक अक्षरों के हर संभव गणितीय संयोजन (combination) को आजमाता है","ब्रूट फोर्स डिक्शनरी अटैक की तुलना में काफी तेज और अधिक लक्षित है","डिक्शनरी अटैक केवल लिनक्स सर्वर पर काम करता है","ब्रूट फोर्स हमले फायरवॉल को लक्षित करते हैं, डिक्शनरी अटैक राउटर को लक्षित करते हैं"],ans:0,exp:"एक डिक्शनरी अटैक अनुकूलित है; यह ज्ञात शब्दों और पैटर्नों की एक विशाल फ़ाइल को हैश करता है, लक्ष्य हैश के विरुद्ध उनका परीक्षण करता है। एक ब्रूट फ़ोर्स हमला मौलिक रूप से विस्तृत होता है, जब तक कि मैच न मिल जाए, तब तक वर्णों के हर एक क्रमिक क्रमपरिवर्तन (permutation) को व्यवस्थित रूप से उत्पन्न और हैश करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In a Public Key Infrastructure (PKI), if an employee's private key is severely compromised, what strict mechanism must the Certificate Authority (CA) utilize to explicitly invalidate their digital certificate before it officially expires?",opts:["Issuing a new IP address","Deleting the user account","Adding the certificate's unique serial number to the Certificate Revocation List (CRL) or responding via OCSP","Formatting the local hard drive"],ans:2,exp:"When a certificate's integrity is compromised (e.g., key theft), the CA must formally revoke it. It does this by appending the certificate's serial number to a published Certificate Revocation List (CRL) or validating its invalid status dynamically via the Online Certificate Status Protocol (OCSP)."},hi:{q:"पब्लिक की इंफ्रास्ट्रक्चर (PKI) में, यदि किसी कर्मचारी की निजी कुंजी से गंभीर समझौता हो जाता है, तो प्रमाणपत्र प्राधिकरण (CA) को डिजिटल प्रमाणपत्र के आधिकारिक तौर पर समाप्त होने से पहले उसे स्पष्ट रूप से अमान्य करने के लिए किस सख्त तंत्र का उपयोग करना चाहिए?",opts:["एक नया IP पता जारी करना","उपयोगकर्ता खाता हटाना","सर्टिफिकेट रिवोकेशन लिस्ट (CRL) में प्रमाणपत्र का अद्वितीय सीरियल नंबर जोड़ना या OCSP के माध्यम से जवाब देना","स्थानीय हार्ड ड्राइव को स्वरूपित (format) करना"],ans:2,exp:"जब किसी प्रमाणपत्र की अखंडता से समझौता किया जाता है (उदा., कुंजी चोरी), तो CA को इसे औपचारिक रूप से रद्द करना चाहिए। यह प्रकाशित सर्टिफिकेट रिवोकेशन लिस्ट (CRL) में प्रमाणपत्र के सीरियल नंबर को जोड़कर या ऑनलाइन सर्टिफिकेट स्टेटस प्रोटोकॉल (OCSP) के माध्यम से गतिशील रूप से इसकी अमान्य स्थिति की पुष्टि करके ऐसा करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In the fundamental Risk Management equation utilized by security analysts, Risk is evaluated mathematically as a function of which two critical interacting factors?",opts:["Cost and Time","Firewall and Antivirus","Threat and Vulnerability (Risk = Threat x Vulnerability)","Hardware and Software"],ans:2,exp:"The canonical Risk Management formula defines Risk as the probability of a Threat exploiting a specific Vulnerability, compounded by the Business Impact. If a system has a massive vulnerability but no credible threat exists to exploit it, the overall calculated risk is significantly reduced."},hi:{q:"सुरक्षा विश्लेषकों द्वारा उपयोग किए जाने वाले मौलिक जोखिम प्रबंधन (Risk Management) समीकरण में, जोखिम का गणितीय मूल्यांकन किन दो महत्वपूर्ण अंतःक्रियात्मक कारकों के फलन के रूप में किया जाता है?",opts:["लागत और समय","फ़ायरवॉल और एंटीवायरस","खतरा और भेद्यता (Risk = Threat x Vulnerability)","हार्डवेयर और सॉफ्टवेयर"],ans:2,exp:"कैनोनिकल रिस्क मैनेजमेंट फॉर्मूला जोखिम को एक विशिष्ट भेद्यता का शोषण करने वाले खतरे की संभावना के रूप में परिभाषित करता है, जो व्यावसायिक प्रभाव (Business Impact) से जुड़ा होता है। यदि किसी सिस्टम में भारी भेद्यता है, लेकिन इसका फायदा उठाने के लिए कोई विश्वसनीय खतरा मौजूद नहीं है, तो समग्र परिकलित जोखिम काफी कम हो जाता है।"}},
{type:"tf",diff:"hard",en:{q:"The Advanced Encryption Standard (AES) heavily utilizes asymmetric cryptography, relying on separate public and private keys to secure bulk data transit.",opts:["True","False"],ans:1,exp:"False. The Advanced Encryption Standard (AES) is strictly a Symmetric key block cipher. It utilizes a single, identical secret key for both the encryption and decryption processes, making it computationally efficient for encrypting massive volumes of bulk data."},hi:{q:"एडवांस्ड एन्क्रिप्शन स्टैंडर्ड (AES) भारी मात्रा में डेटा पारगमन (bulk data transit) को सुरक्षित करने के लिए अलग सार्वजनिक और निजी कुंजी पर निर्भर करते हुए असममित क्रिप्टोग्राफी का भारी उपयोग करता है।",opts:["सही","गलत"],ans:1,exp:"गलत। एडवांस्ड एन्क्रिप्शन स्टैंडर्ड (AES) सख्ती से एक सममित (Symmetric) कुंजी ब्लॉक सिफर है। यह एन्क्रिप्शन और डिक्रिप्शन दोनों प्रक्रियाओं के लिए एक ही, समान गुप्त कुंजी का उपयोग करता है, जिससे यह भारी मात्रा में डेटा को एन्क्रिप्ट करने के लिए कम्प्यूटेशनल रूप से कुशल हो जाता है।"}},
{type:"tf",diff:"hard",en:{q:"In a Mandatory Access Control (MAC) environment, the original end-user who created a highly sensitive file maintains the ultimate authority to dynamically assign or revoke read permissions for their colleagues.",opts:["True","False"],ans:1,exp:"False. In a Mandatory Access Control (MAC) model, authority is strictly centralized. The operating system absolutely overrides end-user intentions by enforcing administrative security labels (e.g., Top Secret). The creator of the file possesses zero discretion to bypass or alter these system-wide access policies."},hi:{q:"एक अनिवार्य एक्सेस कंट्रोल (MAC) वातावरण में, अत्यधिक संवेदनशील फ़ाइल बनाने वाला मूल अंतिम-उपयोगकर्ता अपने सहयोगियों के लिए पठन अनुमतियों (read permissions) को गतिशील रूप से असाइन या रद्द करने का अंतिम अधिकार रखता है।",opts:["सही","गलत"],ans:1,exp:"गलत। अनिवार्य एक्सेस कंट्रोल (MAC) मॉडल में, अधिकार सख्ती से केंद्रीकृत होता है। ऑपरेटिंग सिस्टम प्रशासनिक सुरक्षा लेबल लागू करके अंतिम-उपयोगकर्ता के इरादों को पूरी तरह से ओवरराइड करता है। फ़ाइल के निर्माता के पास इन सिस्टम-व्यापी एक्सेस नीतियों को बायपास करने या बदलने का शून्य विवेक (zero discretion) होता है।"}}
,
{type:"mcq",diff:"medium",en:{q:"What is a 'Zero-Day' vulnerability in cybersecurity?",opts:["A vulnerability fixed within zero days","A security flaw unknown to the software vendor that has no patch available yet","A virus that activates at midnight","A network attack lasting zero seconds"],ans:1,exp:"A Zero-Day vulnerability is a security flaw in software that is unknown to the vendor or developer. Since the vendor has had zero days to fix it, no patch exists. Attackers exploit zero-day vulnerabilities before the developer becomes aware, making them extremely dangerous. They are often sold on dark web markets for high prices and used in targeted attacks against organizations."},hi:{q:"साइबर सुरक्षा में 'Zero-Day' भेद्यता (vulnerability) क्या है?",opts:["शून्य दिनों में ठीक की गई भेद्यता","सॉफ्टवेयर विक्रेता को अज्ञात सुरक्षा खामी जिसके लिए अभी तक कोई पैच उपलब्ध नहीं है","आधी रात को सक्रिय होने वाला वायरस","शून्य सेकंड तक चलने वाला नेटवर्क हमला"],ans:1,exp:"Zero-Day vulnerability सॉफ्टवेयर में एक सुरक्षा खामी है जो विक्रेता या डेवलपर को अज्ञात है। चूँकि विक्रेता के पास इसे ठीक करने के लिए शून्य दिन रहे हैं, इसलिए कोई पैच मौजूद नहीं है। हमलावर इसका फायदा उठाते हैं, जिससे ये अत्यंत खतरनाक होती हैं।"}},
{type:"mcq",diff:"medium",en:{q:"What is 'Multi-Factor Authentication' (MFA)?",opts:["Using multiple passwords for one account","A security process requiring two or more verification factors (password + OTP + biometric) to access an account","Using the same password on multiple sites","A firewall configuration method"],ans:1,exp:"Multi-Factor Authentication (MFA) requires users to provide two or more verification factors before gaining access: something you know (password), something you have (OTP on phone), and something you are (fingerprint/face). Even if a password is stolen, attackers cannot access the account without the additional factors. MFA significantly reduces account compromise risk and is recommended by cybersecurity experts for all important accounts."},hi:{q:"'Multi-Factor Authentication' (MFA) क्या है?",opts:["एक खाते के लिए कई पासवर्ड का उपयोग","एक सुरक्षा प्रक्रिया जिसमें खाते तक पहुँचने के लिए दो या अधिक सत्यापन कारक (पासवर्ड + OTP + बायोमेट्रिक) की आवश्यकता होती है","कई साइटों पर एक ही पासवर्ड का उपयोग","एक फ़ायरवॉल कॉन्फ़िगरेशन विधि"],ans:1,exp:"Multi-Factor Authentication (MFA) के लिए उपयोगकर्ताओं को पहुँच प्राप्त करने से पहले दो या अधिक सत्यापन कारक प्रदान करने की आवश्यकता होती है: कुछ जो आप जानते हैं (पासवर्ड), कुछ जो आपके पास है (फोन पर OTP), और कुछ जो आप हैं (फिंगरप्रिंट/चेहरा)।"}},
{type:"mcq",diff:"medium",en:{q:"What is 'Social Engineering' in the context of cybersecurity attacks?",opts:["Using social media to promote software","Manipulating people psychologically to reveal confidential information or perform actions that compromise security","Building social networking websites","Engineering social media algorithms"],ans:1,exp:"Social Engineering is a cyber attack technique that exploits human psychology rather than technical vulnerabilities. Attackers manipulate victims through deception, impersonation, urgency and trust to reveal passwords, transfer money or install malware. Common forms include phishing emails, vishing (voice calls), pretexting (fake scenarios) and baiting. It is considered one of the most effective attack methods since humans are often the weakest security link."},hi:{q:"साइबर सुरक्षा हमलों के संदर्भ में 'Social Engineering' क्या है?",opts:["सोशल मीडिया का उपयोग करके सॉफ्टवेयर को बढ़ावा देना","लोगों को मनोवैज्ञानिक रूप से गोपनीय जानकारी प्रकट करने या सुरक्षा को खतरे में डालने वाली क्रियाएं करने के लिए हेरफेर करना","सोशल नेटवर्किंग वेबसाइट बनाना","सोशल मीडिया एल्गोरिदम इंजीनियरिंग"],ans:1,exp:"Social Engineering एक साइबर हमला तकनीक है जो तकनीकी कमजोरियों के बजाय मानव मनोविज्ञान का शोषण करती है। हमलावर धोखे, प्रतिरूपण, तात्कालिकता और विश्वास के माध्यम से पीड़ितों को पासवर्ड प्रकट करने, पैसे ट्रांसफर करने या मैलवेयर इंस्टॉल करने के लिए हेरफेर करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"What is a 'VPN' (Virtual Private Network) primarily used for?",opts:["Increasing internet speed","Creating an encrypted tunnel for secure internet communication and hiding IP address","Storing files in the cloud","Creating virtual machines"],ans:1,exp:"A VPN (Virtual Private Network) creates an encrypted tunnel between your device and a VPN server, masking your real IP address and encrypting all internet traffic. It protects data on public WiFi networks, allows access to geo-restricted content, enables secure remote work access to corporate networks and prevents ISPs from monitoring browsing activity. VPNs use protocols like OpenVPN, L2TP/IPSec and WireGuard for encryption."},hi:{q:"'VPN' (Virtual Private Network) का मुख्य रूप से किस लिए उपयोग किया जाता है?",opts:["इंटरनेट स्पीड बढ़ाना","सुरक्षित इंटरनेट संचार के लिए एन्क्रिप्टेड टनल बनाना और IP पता छुपाना","क्लाउड में फाइलें स्टोर करना","वर्चुअल मशीन बनाना"],ans:1,exp:"VPN आपके डिवाइस और VPN सर्वर के बीच एक एन्क्रिप्टेड टनल बनाता है, आपके असली IP पते को छुपाता है और सभी इंटरनेट ट्रैफिक को एन्क्रिप्ट करता है। यह सार्वजनिक WiFi नेटवर्क पर डेटा की रक्षा करता है और सुरक्षित रिमोट कार्य पहुँच सक्षम करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Under the Information Technology Act 2000 (India), which specific Section deals with hacking or unauthorized access to computer systems?",opts:["Section 43 and Section 66","Section 72 only","Section 67 only","Section 65 only"],ans:0,exp:"Under India's IT Act 2000: Section 43 deals with civil liability for unauthorized access, damage, disruption to computer systems (compensation up to Rs 1 crore). Section 66 (IT Amendment Act 2008) makes computer related offences criminal - unauthorized access with dishonest intent is punishable with imprisonment up to 3 years and/or fine up to Rs 5 lakh. Both sections together form the primary legal framework against hacking in India."},hi:{q:"भारत के सूचना प्रौद्योगिकी अधिनियम 2000 (IT Act) के तहत, कौन सी विशिष्ट धारा कंप्यूटर सिस्टम में हैकिंग या अनधिकृत पहुँच से संबंधित है?",opts:["धारा 43 और धारा 66","केवल धारा 72","केवल धारा 67","केवल धारा 65"],ans:0,exp:"भारत के IT Act 2000 के तहत: धारा 43 कंप्यूटर सिस्टम तक अनधिकृत पहुँच, क्षति के लिए नागरिक दायित्व से संबंधित है (1 करोड़ रुपये तक मुआवजा)। धारा 66 (IT संशोधन अधिनियम 2008) कंप्यूटर संबंधी अपराधों को आपराधिक बनाती है - बेईमान इरादे से अनधिकृत पहुँच 3 साल तक कारावास और/या 5 लाख रुपये तक जुर्माने से दंडनीय है।"}},
{type:"mcq",diff:"hard",en:{q:"What is the technical difference between 'Symmetric' and 'Asymmetric' encryption?",opts:["Symmetric is newer; Asymmetric is older","Symmetric uses one key for both encryption and decryption; Asymmetric uses a public key to encrypt and a different private key to decrypt","Symmetric is used for files; Asymmetric for networks only","Symmetric is stronger than Asymmetric in all cases"],ans:1,exp:"Symmetric encryption uses the same secret key for both encrypting and decrypting data (AES, DES). It is fast but requires secure key exchange. Asymmetric encryption uses a key pair: a public key (shared openly) to encrypt and a mathematically linked private key (kept secret) to decrypt (RSA, ECC). HTTPS uses asymmetric to exchange symmetric keys, then uses faster symmetric encryption for data transfer. Asymmetric is slower but solves the key distribution problem."},hi:{q:"'Symmetric' और 'Asymmetric' एन्क्रिप्शन के बीच तकनीकी अंतर क्या है?",opts:["Symmetric नया है; Asymmetric पुराना है","Symmetric एन्क्रिप्शन और डिक्रिप्शन दोनों के लिए एक कुंजी का उपयोग करता है; Asymmetric एन्क्रिप्ट करने के लिए public key और डिक्रिप्ट करने के लिए अलग private key का उपयोग करता है","Symmetric फाइलों के लिए है; Asymmetric केवल नेटवर्क के लिए","Symmetric हर मामले में Asymmetric से मजबूत है"],ans:1,exp:"Symmetric encryption डेटा एन्क्रिप्ट और डिक्रिप्ट करने के लिए एक ही गुप्त कुंजी का उपयोग करता है (AES, DES)। Asymmetric encryption एक key pair का उपयोग करता है: एन्क्रिप्ट करने के लिए public key और डिक्रिप्ट करने के लिए private key (RSA, ECC)। HTTPS सिमेट्रिक keys का आदान-प्रदान करने के लिए Asymmetric का उपयोग करता है।"}},
{type:"mcq",diff:"hard",en:{q:"What is 'SQL Injection' attack and how does it work?",opts:["Injecting SQL database software into a server","Inserting malicious SQL code into input fields to manipulate database queries and gain unauthorized access to data","Overloading a SQL server with requests","Installing SQL Server on a victim's computer"],ans:1,exp:"SQL Injection is a critical web attack where malicious SQL code is inserted into input fields (login forms, search boxes). If the application doesn't sanitize inputs, the injected code becomes part of the SQL query executed on the database. For example, entering ' OR '1'='1 in a login field can bypass authentication. Attackers can extract all data, delete records, or gain admin access. Prevention: parameterized queries, prepared statements, input validation."},hi:{q:"'SQL Injection' हमला क्या है और यह कैसे काम करता है?",opts:["सर्वर में SQL डेटाबेस सॉफ्टवेयर इंजेक्ट करना","डेटाबेस क्वेरी में हेरफेर करने और डेटा तक अनधिकृत पहुँच प्राप्त करने के लिए इनपुट फ़ील्ड में दुर्भावनापूर्ण SQL कोड डालना","SQL सर्वर को अनुरोधों से ओवरलोड करना","पीड़ित के कंप्यूटर पर SQL Server इंस्टॉल करना"],ans:1,exp:"SQL Injection एक महत्वपूर्ण वेब हमला है जहाँ दुर्भावनापूर्ण SQL कोड इनपुट फ़ील्ड में डाला जाता है। उदाहरण के लिए लॉगिन फ़ील्ड में ' OR '1'='1 दर्ज करने से प्रमाणीकरण बाईपास हो सकता है। रोकथाम: parameterized queries, prepared statements, इनपुट validation।"}},
{type:"mcq",diff:"hard",en:{q:"What is 'Ransomware' and what makes it particularly devastating for organizations?",opts:["Software that displays random advertisements","Malware that encrypts victim's files and demands cryptocurrency payment for the decryption key","A virus that randomly deletes system files","Spyware that monitors random websites visited"],ans:1,exp:"Ransomware is malicious software that encrypts all files on infected systems using strong encryption (AES-256 + RSA-2048), making them completely inaccessible. Attackers demand cryptocurrency ransom (Bitcoin/Monero) for the decryption key. It spreads through phishing emails, RDP vulnerabilities, and network shares. It is devastating because: files may never be recovered even after payment, backup systems are often also encrypted, operational downtime costs millions, and reputation damage is severe. WannaCry (2017) and NotPetya are famous examples."},hi:{q:"'Ransomware' क्या है और यह संगठनों के लिए विशेष रूप से विनाशकारी क्यों है?",opts:["यादृच्छिक विज्ञापन प्रदर्शित करने वाला सॉफ्टवेयर","मैलवेयर जो पीड़ित की फाइलों को एन्क्रिप्ट करता है और डिक्रिप्शन key के लिए cryptocurrency भुगतान की मांग करता है","एक वायरस जो सिस्टम फाइलों को यादृच्छिक रूप से हटाता है","स्पाइवेयर जो यादृच्छिक वेबसाइटों की निगरानी करता है"],ans:1,exp:"Ransomware दुर्भावनापूर्ण सॉफ्टवेयर है जो संक्रमित सिस्टम पर सभी फाइलों को मजबूत एन्क्रिप्शन का उपयोग करके एन्क्रिप्ट करता है। हमलावर decryption key के लिए cryptocurrency फिरौती मांगते हैं। WannaCry (2017) और NotPetya प्रसिद्ध उदाहरण हैं।"}},
{type:"mcq",diff:"hard",en:{q:"What is 'Digital Forensics' in cybersecurity and what is its primary objective?",opts:["Creating digital artwork for courtrooms","The process of collecting, preserving, analyzing and presenting digital evidence from electronic devices for legal proceedings","Designing forensic laboratory digital systems","Encrypting digital evidence for court cases"],ans:1,exp:"Digital Forensics is the scientific process of identifying, collecting, preserving, analyzing and presenting digital evidence from computers, mobile phones, networks and storage devices. Primary objectives: recover deleted files, trace hacker activities, establish timeline of events, extract evidence for legal proceedings. Key principles: maintain chain of custody, preserve original evidence integrity using write blockers, create verified forensic images. Used in cybercrime investigations, corporate fraud cases and legal disputes."},hi:{q:"साइबर सुरक्षा में 'Digital Forensics' क्या है और इसका प्राथमिक उद्देश्य क्या है?",opts:["कोर्टरूम के लिए डिजिटल कलाकृति बनाना","कानूनी कार्यवाही के लिए इलेक्ट्रॉनिक उपकरणों से डिजिटल साक्ष्य एकत्र करने, संरक्षित करने, विश्लेषण करने और प्रस्तुत करने की प्रक्रिया","फोरेंसिक प्रयोगशाला डिजिटल सिस्टम डिजाइन करना","अदालती मामलों के लिए डिजिटल साक्ष्य एन्क्रिप्ट करना"],ans:1,exp:"Digital Forensics इलेक्ट्रॉनिक उपकरणों से डिजिटल साक्ष्य की पहचान, संग्रह, संरक्षण, विश्लेषण और प्रस्तुति की वैज्ञानिक प्रक्रिया है। उद्देश्य: हटाई गई फाइलें recover करना, हैकर गतिविधियों का पता लगाना, कानूनी कार्यवाही के लिए साक्ष्य निकालना।"}},
{type:"mcq",diff:"hard",en:{q:"What is the IT Act Section 67 specifically related to in India?",opts:["Unauthorized computer access","Publishing obscene material in electronic form - punishable with 3 years imprisonment and Rs 5 lakh fine for first offence","Data theft from databases","Sending threatening emails"],ans:1,exp:"Section 67 of India's IT Act 2000 specifically deals with publishing or transmitting obscene material in electronic form. First offence: imprisonment up to 3 years AND fine up to Rs 5 lakh. Second and subsequent offences: imprisonment up to 5 years AND fine up to Rs 10 lakh. Section 67A covers sexually explicit material (up to 5 years, Rs 10 lakh first offence) and Section 67B specifically addresses child pornography with stricter penalties under POCSO Act."},hi:{q:"भारत में IT Act की धारा 67 विशेष रूप से किससे संबंधित है?",opts:["अनधिकृत कंप्यूटर पहुँच","इलेक्ट्रॉनिक रूप में अश्लील सामग्री प्रकाशित करना - पहले अपराध के लिए 3 साल कारावास और 5 लाख रुपये जुर्माना","डेटाबेस से डेटा चोरी","धमकी भरे ईमेल भेजना"],ans:1,exp:"भारत के IT Act 2000 की धारा 67 विशेष रूप से इलेक्ट्रॉनिक रूप में अश्लील सामग्री प्रकाशित या प्रसारित करने से संबंधित है। पहला अपराध: 3 साल तक कारावास और 5 लाख रुपये तक जुर्माना। धारा 67A यौन स्पष्ट सामग्री को कवर करती है और धारा 67B बाल अश्लीलता को।"}}
];